function formatDuration(ms: number): string {
  const totalSec = Math.max(0, Math.floor(ms / 1000));
  const m = Math.floor(totalSec / 60);
  const s = totalSec % 60;
  return m > 0 ? `${m}:${String(s).padStart(2, '0')}` : `${s} с`;
}

function showCrowdLine(text: string): void {
  const el = document.getElementById('crowd-line');
  if (!el) return;
  el.hidden = false;
  el.textContent = text;
  lastCrowdAt = Date.now();
  const shownAt = lastCrowdAt;
  window.setTimeout(() => {
    if (lastCrowdAt === shownAt) el.hidden = true;
  }, 2800);
}

function spawnDamageFloat(amount = 1): void {
  const stage = document.querySelector('.raid-stage');
  const host = document.getElementById('dmg-float');
  if (!stage) return;
  const el = document.createElement('div');
  el.className = 'dmg-float show';
  el.textContent = `-${amount}`;
  const x = 18 + Math.random() * 54;
  el.style.left = `${x}%`;
  stage.appendChild(el);
  window.setTimeout(() => el.remove(), 700);
  if (host) {
    host.hidden = true;
  }
}

