function bindPoster(): void {
  document.getElementById('btn-poster-back')?.addEventListener('click', () => {
    homeTab = 'battle';
    screen = 'home';
    render();
  });
  document.getElementById('btn-poster-go')?.addEventListener('click', () => {
    setupReadySince = null;
    setupCountdownDone = false;
    setupCountdownSoundSec = null;
    screen = 'setup';
    render();
  });
}

function bindHome(): void {
  document.getElementById('btn-camera')?.addEventListener('click', () => {
    void requestCameraAccess();
  });
  document.getElementById('btn-camera-nudge')?.addEventListener('click', () => {
    homeTab = 'profile';
    render();
  });

  app.querySelectorAll<HTMLButtonElement>('[data-exercise]').forEach((btn) => {
    btn.addEventListener('click', () => {
      const id = btn.dataset.exercise as ExerciseId;
      if (id !== 'pushup' && id !== 'squat') return;
      selectedExercise = id;
      try {
        localStorage.setItem('moveboss-exercise', id);
      } catch {
        /* ignore */
      }
      render();
    });
  });

  app.querySelectorAll<HTMLButtonElement>('[data-tab]').forEach((btn) => {
    btn.addEventListener('click', () => {
      homeTab = btn.dataset.tab as HomeTab;
      if (homeTab === 'rating' && leaderboardCache === null) {
        void refreshLeaderboard().then(() => {
          if (homeTab === 'rating' && screen === 'home') render();
        });
      }
      if (homeTab === 'profile' || homeTab === 'rating') {
        /* keep auth/msg state */
      }
      render();
    });
  });

  app.querySelectorAll<HTMLButtonElement>('[data-list]').forEach((btn) => {
    btn.addEventListener('click', () => {
      const mode = btn.dataset.list;
      if (mode === 'arenas' || mode === 'challenges') {
        homeListMode = mode;
        render();
      }
    });
  });

  document.getElementById('btn-refresh-lb')?.addEventListener('click', () => {
    void refreshLeaderboard().then(() => render());
  });

  const runAuth = async (mode: 'register' | 'login') => {
    const nick = (document.getElementById('auth-nick') as HTMLInputElement | null)?.value || '';
    const pass = (document.getElementById('auth-pass') as HTMLInputElement | null)?.value || '';
    authBusy = true;
    authMessage = '';
    render();
    try {
      const nickTrim = nick.trim();
      const payload = {
        nickname: nickTrim,
        password: pass,
        displayName: nickTrim,
        profile: { ...loadProfile(), name: nickTrim },
        progress: loadProgress()
      };
      const data =
        mode === 'register' ? await registerAccount(payload) : await loginAccount(payload);
      mergeServerProgress(data.progress);
      mergeServerProfile({
        displayName: data.player.displayName || data.player.nickname,
        streakDays: data.player.streakDays,
        lifetimeReps: data.player.lifetimeReps,
        lastActiveDay: data.player.lastActiveDay
      });
      setAthleteName(data.player.nickname);
      authMessage = mode === 'register' ? 'Аккаунт создан — ты в таблице' : 'Вход выполнен';
      authMessageOk = true;
      await refreshLeaderboard();
    } catch (e) {
      authMessage = e instanceof Error ? e.message : 'Ошибка';
      authMessageOk = false;
    } finally {
      authBusy = false;
      render();
    }
  };

  document.getElementById('btn-register')?.addEventListener('click', () => {
    void runAuth('register');
  });
  document.getElementById('btn-login')?.addEventListener('click', () => {
    void runAuth('login');
  });
  document.getElementById('btn-logout')?.addEventListener('click', () => {
    void logoutAccount().then(() => {
      authMessage = 'Вышел из аккаунта. Локальный прогресс на месте.';
      authMessageOk = true;
      render();
    });
  });

  app.querySelectorAll<HTMLButtonElement>('[data-level]').forEach((btn) => {
    btn.addEventListener('click', () => {
      if (!cameraReady) return;
      const levelId = btn.dataset.level as LevelId;
      if (!isLevelUnlocked(levelId)) return;
      playMode = 'arena';
      activeLevel = getLevel(levelId);
      activeChallenge = null;
      foeIndex = 0;
      damage = 0;
      phase = 'unknown';
      poseFound = false;
      lastHint = '';
      resetArenaRunCounters();
      screen = 'poster';
      render();
    });
  });

  app.querySelectorAll<HTMLButtonElement>('[data-challenge]').forEach((btn) => {
    btn.addEventListener('click', () => {
      if (!cameraReady) return;
      playMode = 'challenge';
      activeChallenge = getChallenge(btn.dataset.challenge as ChallengeId);
      activeLevel = null;
      foeIndex = 0;
      damage = 0;
      phase = 'unknown';
      poseFound = false;
      lastHint = '';
      challengeWon = false;
      if (activeChallenge.mode === 'endurance' && selectedExercise !== 'pushup') {
        selectedExercise = 'pushup';
      }
      screen = 'poster';
      render();
    });
  });
}

