/**
 * Front-camera squat signals — visibility-weighted legs, hip depth, knee angle.
 * Rejects approach/retreat (body scale change) without real knee bend.
 */

export type SquatLm = { x: number; y: number; z?: number; visibility?: number };

export interface SquatPoseResult {
  landmarkOk: boolean;
  kneeAngle: number;
  /** hip.y − knee.y (positive when hip at/below knee in image Y-down) */
  hipDepth: number;
  /** Mid-shoulder → mid-ankle length in normalized coords (grows when walking closer) */
  bodySpan: number;
  standing: boolean;
  atBottom: boolean;
  hint: string;
  leftVis: number;
  rightVis: number;
}

function vis(lm: SquatLm | undefined): number {
  if (!lm || !Number.isFinite(lm.x) || !Number.isFinite(lm.y)) return 0;
  return typeof lm.visibility === 'number' ? lm.visibility : 0.55;
}

function mid(a: SquatLm, b: SquatLm): SquatLm {
  return { x: (a.x + b.x) / 2, y: (a.y + b.y) / 2, visibility: Math.min(vis(a), vis(b)) };
}

function angleDeg(ax: number, ay: number, bx: number, by: number, cx: number, cy: number): number {
  const v1x = ax - bx;
  const v1y = ay - by;
  const v2x = cx - bx;
  const v2y = cy - by;
  const dot = v1x * v2x + v1y * v2y;
  const n1 = Math.hypot(v1x, v1y);
  const n2 = Math.hypot(v2x, v2y);
  if (n1 < 1e-6 || n2 < 1e-6) return 180;
  const cos = Math.min(1, Math.max(-1, dot / (n1 * n2)));
  return (Math.acos(cos) * 180) / Math.PI;
}

const MIN_JOINT = 0.35;
const MIN_LEG = 0.32;

/** Absolute knee bend required for a real squat bottom (not approach noise). */
export const SQUAT_BOTTOM_ANGLE = 112;
export const SQUAT_STAND_ANGLE = 152;

function legScore(hip: SquatLm, knee: SquatLm, ankle: SquatLm): number {
  return Math.min(vis(hip), vis(knee), vis(ankle));
}

export function evaluateSquatPose(lm: SquatLm[]): SquatPoseResult {
  const lh = lm[23];
  const rh = lm[24];
  const lk = lm[25];
  const rk = lm[26];
  const la = lm[27];
  const ra = lm[28];
  const ls = lm[11];
  const rs = lm[12];

  const leftScore = lh && lk && la ? legScore(lh, lk, la) : 0;
  const rightScore = rh && rk && ra ? legScore(rh, rk, ra) : 0;

  let kneeAngle = 180;
  let hipDepth = -1;
  const angles: number[] = [];

  const takeLeft = leftScore >= MIN_LEG;
  const takeRight = rightScore >= MIN_LEG;

  if (takeLeft && lh && lk && la) {
    angles.push(angleDeg(lh.x, lh.y, lk.x, lk.y, la.x, la.y));
    hipDepth = Math.max(hipDepth, lh.y - lk.y);
  }
  if (takeRight && rh && rk && ra) {
    angles.push(angleDeg(rh.x, rh.y, rk.x, rk.y, ra.x, ra.y));
    hipDepth = Math.max(hipDepth, rh.y - rk.y);
  }

  if (angles.length === 0) {
    if (lh && lk && la && Number.isFinite(lh.x)) {
      angles.push(angleDeg(lh.x, lh.y, lk.x, lk.y, la.x, la.y));
      hipDepth = Math.max(hipDepth, lh.y - lk.y);
    }
    if (rh && rk && ra && Number.isFinite(rh.x)) {
      angles.push(angleDeg(rh.x, rh.y, rk.x, rk.y, ra.x, ra.y));
      hipDepth = Math.max(hipDepth, rh.y - rk.y);
    }
  }

  if (angles.length > 0) {
    kneeAngle = Math.min(...angles);
  }

  let bodySpan = 0;
  if (ls && rs && la && ra && Number.isFinite(ls.x) && Number.isFinite(la.x)) {
    const sh = mid(ls, rs);
    const an = mid(la, ra);
    bodySpan = Math.hypot(an.x - sh.x, an.y - sh.y);
  } else if (ls && rs && lh && rh) {
    const sh = mid(ls, rs);
    const hp = mid(lh, rh);
    bodySpan = Math.hypot(hp.x - sh.x, hp.y - sh.y) * 2.2;
  }

  const hipOk =
    vis(lh) >= MIN_JOINT ||
    vis(rh) >= MIN_JOINT ||
    (lh && rh && Number.isFinite(lh.x) && Number.isFinite(rh.x));
  const kneeOk = vis(lk) >= MIN_JOINT || vis(rk) >= MIN_JOINT;
  const ankleOk = leftScore >= MIN_LEG || rightScore >= MIN_LEG;
  const shoulderOk = vis(ls) >= 0.25 || vis(rs) >= 0.25;

  const landmarkOk = hipOk && kneeOk && ankleOk && shoulderOk && angles.length > 0;

  // Real squat bottom: clear knee bend + hips dropping toward knee line
  const standing = landmarkOk && kneeAngle >= SQUAT_STAND_ANGLE && hipDepth < 0.05;
  const atBottom =
    landmarkOk &&
    kneeAngle <= SQUAT_BOTTOM_ANGLE &&
    hipDepth >= -0.05;

  let hint = 'Стойка — можно садиться';
  if (!ankleOk) hint = 'Отойди — стопы и колени в кадре';
  else if (!landmarkOk) hint = 'Ноги в кадре · весь рост';
  else if (atBottom) hint = 'Низ ✓ — встань вверх';
  else if (kneeAngle < 140) hint = 'Глубже — согни колени';
  else if (standing) hint = 'Стойка — можно садиться';

  return {
    landmarkOk,
    kneeAngle,
    hipDepth,
    bodySpan,
    standing,
    atBottom,
    hint,
    leftVis: leftScore,
    rightVis: rightScore
  };
}
