export type RepPhase = 'unknown' | 'up' | 'down';

export interface RepPhaseInfo {
  exercise: ExerciseId;
  angle: number;
  depth: number;
  depthOk: boolean;
  angleOkDown: boolean;
  angleOkUp: boolean;
  hint: string;
  /** Compact live metrics for HUD (push-ups). */
  debugLine?: string;
  /** false = pose rejected (e.g. standing during push-ups) */
  poseOk?: boolean;
  /** Push-up face-on: straighter-arm angle for lockout/recover */
  armAngleUp?: number;
  /** Push-up: at least one elbow reached depth */
  elbowAtDepth?: boolean;
  leftElbowY?: number;
  rightElbowY?: number;
  elbowWidth?: number;
  elbowLateral?: number;
  flareRatio?: number;
  bodyLineOk?: boolean;
  bodyLineKnown?: boolean;
  /** Standing / holding phone — disarm immediately */
  isStanding?: boolean;
  upperArmHorizontal?: boolean;
  shoulderWristDist?: number;
  shoulderAngle?: number;
  leftArmAngle?: number;
  rightArmAngle?: number;
  leftArmOk?: boolean;
  rightArmOk?: boolean;
  leftWristX?: number;
  leftWristY?: number;
  rightWristX?: number;
  rightWristY?: number;
  bodyLineHardFail?: boolean;
  /** Crunch extras */
  torsoOk?: boolean;
  armMode?: string;
  isSitUpLike?: boolean;
  failReason?: string | null;
  /** Squat: shoulder→ankle span (normalized) */
  bodySpan?: number;
}

export interface RepDetectorOptions {
  exercise: ExerciseId;
  /** fight = count reps; setup = only framing checks */
  mode?: 'fight' | 'setup';
  /** Push-up sensitivity preset */
  pushupStrictness?: PushupStrictness;
  onRep: (total: number) => void;
  onPhase: (phase: RepPhase, info: RepPhaseInfo) => void;
  onPose: (found: boolean) => void;
  onSetup?: (result: SetupResult) => void;
}

