function angleDeg(
  ax: number,
  ay: number,
  bx: number,
  by: number,
  cx: number,
  cy: number
): number {
  const v1x = ax - bx;
  const v1y = ay - by;
  const v2x = cx - bx;
  const v2y = cy - by;
  const dot = v1x * v2x + v1y * v2y;
  const n1 = Math.hypot(v1x, v1y);
  const n2 = Math.hypot(v2x, v2y);
  if (n1 < 1e-6 || n2 < 1e-6) return 180;
  const cos = Math.min(1, Math.max(-1, dot / (n1 * n2)));
  return (Math.acos(cos) * 180) / Math.PI;
}

function mid(a: NormalizedLandmark, b: NormalizedLandmark): { x: number; y: number } {
  return { x: (a.x + b.x) / 2, y: (a.y + b.y) / 2 };
}

/** Generic rep counter for push-up / squat / crunch / burpee */
export class RepDetector {
  private landmarker: PoseLandmarker | null = null;
  private running = false;
  private raf = 0;
  private phase: RepPhase = 'unknown';
  private reps = 0;
  private downFrames = 0;
  private upFrames = 0;
  private burpeeSawPlank = false;
  private lastRepAt = 0;
  private pushupPoseBadFrames = 0;
  /** After leaving plank, unfinished down is stopped; must re-arm before a new down */
  private pushupArmed = true;
  private pushupPlankHoldFrames = 0;
  /** GoUp-style push-up state — crunch uses dedicated filters */
  private crunchFlat: CrunchFlatBaseline = {
    lift: 0,
    elevDeg: 4,
    torsoLen: 0.28
  };
  private crunchCalibFrames = 0;
  /** Slow accurate + fast reactive (как отжимания) */
  private crunchSlowFilter = new OneEuroFilter(1.0, 0.008, 1.0);
  private crunchFastFilter = new OneEuroFilter(2.6, 0.05, 1.0);
  private crunchCurlSlow = 0;
  private crunchCurlFast = 0;
  /** flat | rising | peak | lowering */
  private crunchStage: 'flat' | 'rising' | 'peak' | 'lowering' = 'flat';
  private crunchPrevCurl = 0;
  private crunchPeakHoldFrames = 0;
  private crunchNeedFlatLock = false;
  private crunchLockUntil = 0;
  private crunchWristX = 0;
  private crunchWristY = 0;
  private crunchWristSpeed = 0;
  private crunchLastT = 0;
  private crunchRepCredited = false;
  /** Squat: filtered knee angle + personal standing lockout */
  private squatSlowFilter = new OneEuroFilter(1.0, 0.01, 1.0);
  private squatTop = 165;
  private squatSawBottom = false;
  private squatMinAngle = 180;
  private squatBottomHold = 0;
  /** Body span at standing lock — reject walk-in if span grows without deep knees */
  private squatStandSpan = 0;
  private squatSpanAtDown = 0;
  private squatStandHold = 0;
  private squatApproachReject = false;
  /** GoUp-style push-up state */
  private pushTopAngle = 160;
  private pushBottomAngle = 180;
  private pushDownFrames = 0;
  private pushFramesSinceRep = 999;
  /** Slow / accurate angle (1€) */
  private pushSlowFilter = new OneEuroFilter(1.0, 0.007, 1.0);
  /** Fast / reactive angle (1€) */
  private pushFastFilter = new OneEuroFilter(2.8, 0.05, 1.0);
  private pushAngleEma = 160;
  private pushAngleFast = 160;
  /** Absolute min angle seen this down (raw) */
  private pushRawMin = 180;
  /** Rep finished rise but still inside cooldown — count when cooled */
  private pushPendingRep = false;
  /**
   * After a count (or pending park), block new downs until true lockout.
   * Without this, a small rise at the bottom re-enters DOWN and multi-counts.
   */
  private pushNeedLockout = false;
  /** Frames to ignore DOWN right after lockout clears (top wobble → fake 2nd rep). */
  private pushLockoutGrace = 0;
  /** This down-cycle already produced a rep — never double-credit until next down. */
  private pushRepCredited = false;
  /** True once this down-rep saw at least one elbow at depth */
  private pushSawElbowDepth = false;
  private pushSawElbowAtLevel = false;
  private pushElbowY0L = 0;
  private pushElbowY0R = 0;
  private pushMaxElbowDescent = 0;
  private pushElbowWidth0 = 0;
  private pushMaxElbowWidth = 0;
  private pushElbowLateral0 = 0;
  private pushMaxElbowLateral = 0;
  private pushFlareRatio0 = 1;
  private pushMaxFlareRatio = 1;
  private pushShoulderWrist0 = 0;
  private pushMinShoulderWrist = 1;
  /** Top angle locked when entering this down — restored on abort */
  private pushTopAtEnter = 160;
  private pushUpHoldFrames = 0;
  private pushBodyLinePoor = false;
  private pushBodyLineHard = false;
  private pushWristX0L = 0;
  private pushWristY0L = 0;
  private pushWristX0R = 0;
  private pushWristY0R = 0;
  private pushMaxWristShift = 0;
  private pushDownStartedAt = 0;
  private pushDepthReachedAt = 0;
  /** Dwell at bottom frozen when rise starts (ms). */
  private pushBottomDwellMs = 0;
  private pushStrictness: PushupStrictness;
  private readonly opts: RepDetectorOptions;
  private canvas: HTMLCanvasElement | null = null;
  private video: HTMLVideoElement | null = null;

  /** Reuse one PoseLandmarker across setup → fight (reload was the long pause). */
  private static cachedLandmarker: PoseLandmarker | null = null;
  private static warmPromise: Promise<PoseLandmarker> | null = null;

  constructor(opts: RepDetectorOptions) {
    this.opts = opts;
    this.pushStrictness = opts.pushupStrictness ?? 'normal';
  }

  setPushupStrictness(level: PushupStrictness): void {
    this.pushStrictness = level;
  }

  getReps(): number {
    return this.reps;
  }

  /** true when model is already in memory */
  static isModelReady(): boolean {
    return RepDetector.cachedLandmarker != null;
  }

  /** Prefetch pose model in background (camera gate / setup). */
  static warmUp(): Promise<PoseLandmarker> {
    if (RepDetector.cachedLandmarker) {
      return Promise.resolve(RepDetector.cachedLandmarker);
    }
    if (RepDetector.warmPromise) return RepDetector.warmPromise;
    RepDetector.warmPromise = (async () => {
      const vision = await FilesetResolver.forVisionTasks(
        'https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@0.10.21/wasm'
      );
      const common = {
        runningMode: 'VIDEO' as const,
        numPoses: 1,
        minPoseDetectionConfidence: 0.4,
        minPosePresenceConfidence: 0.4,
        minTrackingConfidence: 0.45
      };
      const models = [
        'https://storage.googleapis.com/mediapipe-models/pose_landmarker/pose_landmarker_full/float16/1/pose_landmarker_full.task',
        'https://storage.googleapis.com/mediapipe-models/pose_landmarker/pose_landmarker_lite/float16/1/pose_landmarker_lite.task',
        'https://storage.googleapis.com/mediapipe-models/pose_landmarker/pose_landmarker_heavy/float16/1/pose_landmarker_heavy.task'
      ];
      let lastErr: unknown = null;
      for (const modelAssetPath of models) {
        for (const delegate of ['GPU', 'CPU'] as const) {
          try {
            const lm = await PoseLandmarker.createFromOptions(vision, {
              ...common,
              baseOptions: { modelAssetPath, delegate }
            });
            RepDetector.cachedLandmarker = lm;
            return lm;
          } catch (e) {
            lastErr = e;
          }
        }
      }
      RepDetector.warmPromise = null;
      throw lastErr instanceof Error ? lastErr : new Error('Pose landmarker init failed');
    })().catch((err) => {
      RepDetector.warmPromise = null;
      throw err;
    });
    return RepDetector.warmPromise;
  }

  reset(): void {
    this.reps = 0;
    this.phase = 'unknown';
    this.downFrames = 0;
    this.upFrames = 0;
    this.burpeeSawPlank = false;
    this.lastRepAt = 0;
    this.pushupPoseBadFrames = 0;
    this.pushupArmed = this.opts.exercise !== 'pushup';
    this.pushupPlankHoldFrames = 0;
    this.crunchFlat = {
      lift: 0,
      elevDeg: 4,
      torsoLen: 0.28
    };
    this.crunchCalibFrames = 0;
    this.crunchSlowFilter.reset(0);
    this.crunchFastFilter.reset(0);
    this.crunchCurlSlow = 0;
    this.crunchCurlFast = 0;
    this.crunchStage = 'flat';
    this.crunchPrevCurl = 0;
    this.crunchPeakHoldFrames = 0;
    this.crunchNeedFlatLock = false;
    this.crunchLockUntil = 0;
    this.crunchWristX = 0;
    this.crunchWristY = 0;
    this.crunchWristSpeed = 0;
    this.crunchLastT = 0;
    this.crunchRepCredited = false;
    this.squatSlowFilter.reset(165);
    this.squatTop = 165;
    this.squatSawBottom = false;
    this.squatMinAngle = 180;
    this.squatBottomHold = 0;
    this.squatStandSpan = 0;
    this.squatSpanAtDown = 0;
    this.squatStandHold = 0;
    this.squatApproachReject = false;
    this.pushTopAngle = 160;
    this.pushBottomAngle = 180;
    this.pushDownFrames = 0;
    this.pushFramesSinceRep = 999;
    this.pushSlowFilter.reset(160);
    this.pushFastFilter.reset(160);
    this.pushAngleEma = 160;
    this.pushAngleFast = 160;
    this.pushRawMin = 180;
    this.pushPendingRep = false;
    this.pushNeedLockout = false;
    this.pushLockoutGrace = 0;
    this.pushRepCredited = false;
    this.pushSawElbowDepth = false;
    this.pushSawElbowAtLevel = false;
    this.pushElbowY0L = 0;
    this.pushElbowY0R = 0;
    this.pushMaxElbowDescent = 0;
    this.pushElbowWidth0 = 0;
    this.pushMaxElbowWidth = 0;
    this.pushElbowLateral0 = 0;
    this.pushMaxElbowLateral = 0;
    this.pushFlareRatio0 = 1;
    this.pushMaxFlareRatio = 1;
    this.pushShoulderWrist0 = 0;
    this.pushMinShoulderWrist = 1;
    this.pushTopAtEnter = 160;
    this.pushUpHoldFrames = 0;
    this.pushBodyLinePoor = false;
    this.pushBodyLineHard = false;
    this.pushWristX0L = 0;
    this.pushWristY0L = 0;
    this.pushWristX0R = 0;
    this.pushWristY0R = 0;
    this.pushMaxWristShift = 0;
    this.pushDownStartedAt = 0;
    this.pushDepthReachedAt = 0;
    this.pushBottomDwellMs = 0;
  }

  async init(): Promise<void> {
    if (RepDetector.cachedLandmarker) {
      this.landmarker = RepDetector.cachedLandmarker;
      return;
    }
    this.landmarker = await RepDetector.warmUp();
  }

  start(video: HTMLVideoElement, canvas?: HTMLCanvasElement | null): void {
    if (!this.landmarker) throw new Error('Detector not initialized');
    this.video = video;
    this.canvas = canvas ?? null;
    this.running = true;
    const tick = () => {
      if (!this.running || !this.landmarker || !this.video) return;
      if (this.video.readyState >= 2) {
        const result = this.landmarker.detectForVideo(this.video, performance.now());
        this.handleResult(result);
      }
      this.raf = requestAnimationFrame(tick);
    };
    this.raf = requestAnimationFrame(tick);
  }

  stop(): void {
    this.running = false;
    cancelAnimationFrame(this.raf);
    const ctx = this.canvas?.getContext('2d');
    if (ctx && this.canvas) ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);
    this.canvas = null;
    this.video = null;
  }

  private handleResult(result: PoseLandmarkerResult): void {
    const lm = result.landmarks?.[0];
    if (!lm || lm.length < 29) {
      this.clearCanvas();
      this.opts.onPose(false);
      if (this.opts.mode === 'setup') {
        this.opts.onSetup?.(evaluateCameraSetup(this.opts.exercise, undefined));
      }
      return;
    }
    this.opts.onPose(true);
    this.drawPose(lm);

    if (this.opts.mode === 'setup') {
      this.opts.onSetup?.(evaluateCameraSetup(this.opts.exercise, lm));
      return;
    }

    const world = result.worldLandmarks?.[0] ?? null;
    const evaled = this.evaluate(lm, world);
    this.applyPhaseMachine(evaled.isDown, evaled.isUp, evaled.info);
  }

  private evaluate(
    lm: NormalizedLandmark[],
    world?: NormalizedLandmark[] | null
  ): {
    isDown: boolean;
    isUp: boolean;
    info: RepPhaseInfo;
  } {
    switch (this.opts.exercise) {
      case 'squat':
        return this.evalSquat(lm);
      case 'crunch':
        return this.evalCrunch(lm);
      case 'burpee':
        return this.evalBurpee(lm);
      case 'pushup':
      default:
        return this.evalPushup(lm, world);
    }
  }

  /**
   * Push-up: angle = more-bent arm, depth = elbow drop, armAngleUp = straighter arm.
   */
  private evalPushup(lm: NormalizedLandmark[], world?: NormalizedLandmark[] | null) {
    const p = evaluatePushupPose(lm, world);
    const info: RepPhaseInfo = {
      exercise: 'pushup',
      angle: p.armAngleDown,
      depth: p.elbowDrop,
      depthOk: true,
      angleOkDown: false,
      angleOkUp: false,
      hint: p.hintFight,
      poseOk: p.inPlank,
      armAngleUp: p.armAngleUp,
      elbowAtDepth: p.elbowAtDepth,
      leftElbowY: p.leftElbowY,
      rightElbowY: p.rightElbowY,
      elbowWidth: p.elbowWidth,
      elbowLateral: p.elbowLateral,
      flareRatio: p.flareRatio,
      bodyLineOk: p.bodyLineOk,
      bodyLineKnown: p.bodyLineKnown,
      isStanding: p.isStanding,
      upperArmHorizontal: p.upperArmHorizontal,
      shoulderWristDist: p.shoulderWristDist,
      shoulderAngle: p.shoulderAngle,
      leftArmAngle: p.leftArmAngle,
      rightArmAngle: p.rightArmAngle,
      leftArmOk: p.leftArmOk,
      rightArmOk: p.rightArmOk,
      leftWristX: p.leftWristX,
      leftWristY: p.leftWristY,
      rightWristX: p.rightWristX,
      rightWristY: p.rightWristY,
      bodyLineHardFail: p.bodyLineHardFail
    };
    return { isDown: false, isUp: false, info };
  }

  private evalSquat(lm: NormalizedLandmark[]) {
    const s = evaluateSquatPose(lm);
    const info: RepPhaseInfo = {
      exercise: 'squat',
      angle: s.kneeAngle,
      depth: s.hipDepth,
      depthOk: s.hipDepth >= -0.05,
      angleOkDown: s.atBottom,
      angleOkUp: s.standing,
      hint: s.hint,
      poseOk: s.landmarkOk,
      bodySpan: s.bodySpan
    };
    return { isDown: s.atBottom, isUp: s.standing, info };
  }

  /**
   * Crunch: подъём плеч выше таза; bent/straight пороги внутри evaluate.
   */
  private evalCrunch(lm: NormalizedLandmark[]) {
    const now = performance.now();
    const wrist = mid(lm[15], lm[16]);
    if (this.crunchLastT > 0) {
      const dt = Math.max(0.016, (now - this.crunchLastT) / 1000);
      const dist = Math.hypot(wrist.x - this.crunchWristX, wrist.y - this.crunchWristY);
      this.crunchWristSpeed = 0.65 * this.crunchWristSpeed + 0.35 * (dist / dt);
    }
    this.crunchWristX = wrist.x;
    this.crunchWristY = wrist.y;
    this.crunchLastT = now;

    const peek = evaluateCrunchPose(lm, this.crunchFlat, this.crunchWristSpeed);
    const canCalib =
      peek.oriented &&
      peek.landmarkOk &&
      peek.armMode !== 'swing' &&
      peek.curl <= CRUNCH_FLAT_ENTER + 0.08;
    if (canCalib) {
      this.crunchCalibFrames += 1;
      const a = this.crunchCalibFrames <= 40 ? 0.3 : 0.05;
      this.crunchFlat = {
        lift: this.crunchFlat.lift * (1 - a) + peek.lift * a,
        elevDeg: this.crunchFlat.elevDeg * (1 - a) + peek.elevDeg * a,
        torsoLen: Math.max(
          0.08,
          this.crunchFlat.torsoLen * (1 - a) + peek.torsoLen * a
        )
      };
    }

    const c = evaluateCrunchPose(lm, this.crunchFlat, this.crunchWristSpeed);
    const atPeak = c.oriented && c.torsoOk && c.curl >= CRUNCH_PEAK_ENTER;
    const atFlat = c.oriented && c.curl <= CRUNCH_FLAT_ENTER;
    const info: RepPhaseInfo = {
      exercise: 'crunch',
      angle: c.elevDeg,
      depth: c.curl,
      depthOk: c.oriented && c.hipsStable,
      angleOkDown: atPeak,
      angleOkUp: atFlat,
      hint: c.hint,
      poseOk: c.oriented && c.landmarkOk,
      torsoOk: c.torsoOk,
      armMode: c.armMode,
      isSitUpLike: c.isSitUpLike,
      failReason: c.failReason
    };
    return { isDown: atPeak, isUp: atFlat, info };
  }

  /**
   * Burpee: hip height + rough plank/stand poses.
   * Works better from front/45° phone camera than strict side-plank geometry.
   */
  private evalBurpee(lm: NormalizedLandmark[]) {
    const shoulder = mid(lm[11], lm[12]);
    const hip = mid(lm[23], lm[24]);
    const wrist = mid(lm[15], lm[16]);
    const lKnee = angleDeg(lm[23].x, lm[23].y, lm[25].x, lm[25].y, lm[27].x, lm[27].y);
    const rKnee = angleDeg(lm[24].x, lm[24].y, lm[26].x, lm[26].y, lm[28].x, lm[28].y);
    const knee = Math.min(lKnee, rKnee);

    const torsoFlat = Math.abs(shoulder.y - hip.y) < 0.18;
    const hipsLow = hip.y > 0.48;
    const handsLow = wrist.y > shoulder.y + 0.05;
    // "On the ground" — plank OR deep squat/kickback (any clear low position)
    const isDown =
      (hipsLow && torsoFlat) ||
      (hipsLow && handsLow) ||
      (hip.y > 0.62 && knee < 150);

    // Standing tall again
    const isUp =
      hip.y < 0.52 &&
      knee > 125 &&
      hip.y < shoulder.y + 0.02;

    const angle = knee;
    const depth = hip.y - shoulder.y;

    const info: RepPhaseInfo = {
      exercise: 'burpee',
      angle,
      depth,
      depthOk: isDown,
      angleOkDown: isDown,
      angleOkUp: isUp,
      hint: isDown
        ? 'Низ / упор ✓ — встань в стойку'
        : isUp
          ? this.burpeeSawPlank
            ? 'Стойка ✓ — можно снова вниз'
            : 'Стойка ✓ — упади вниз в упор'
          : 'Сделай чётче: стойка ↔ низ (упор/присед)'
    };

    return { isDown, isUp, info };
  }

  private applyPhaseMachine(isDown: boolean, isUp: boolean, info: RepPhaseInfo): void {
    const ex = this.opts.exercise;
    if (ex === 'pushup') {
      this.applyPushupMachine(info);
      return;
    }
    if (ex === 'crunch') {
      this.applyCrunchMachine(info);
      return;
    }
    if (ex === 'squat') {
      this.applySquatMachine(info);
      return;
    }

    const STABLE = 2;
    const isBurpee = ex === 'burpee';

    if (isDown) {
      this.downFrames += 1;
      this.upFrames = 0;
      if (this.downFrames >= STABLE) {
        if (isBurpee) this.burpeeSawPlank = true;
        if (this.phase !== 'down') this.phase = 'down';
        this.opts.onPhase('down', info);
      } else {
        this.opts.onPhase(this.phase, info);
      }
      return;
    }

    if (isUp) {
      this.upFrames += 1;
      this.downFrames = 0;
      if (this.upFrames >= STABLE) {
        const now = performance.now();
        if (isBurpee) {
          if (this.burpeeSawPlank) {
            this.reps += 1;
            this.burpeeSawPlank = false;
            this.lastRepAt = now;
            this.opts.onRep(this.reps);
          }
        } else if (this.phase === 'down') {
          this.reps += 1;
          this.lastRepAt = now;
          this.opts.onRep(this.reps);
        }
        if (this.phase !== 'up') this.phase = 'up';
        this.opts.onPhase('up', info);
      } else {
        this.opts.onPhase(this.phase, info);
      }
      return;
    }

    if (this.downFrames > 0) this.downFrames -= 1;
    if (this.upFrames > 0) this.upFrames -= 1;
    this.opts.onPhase(this.phase, info);
  }

  /**
   * Front-camera squat with anti-approach gate.
   * Walk toward/away changes bodySpan; real squat needs absolute knee bend.
   */
  private applySquatMachine(info: RepPhaseInfo): void {
    const now = performance.now();
    const landmarkOk = info.poseOk === true;
    const raw = info.angle;
    const filtered = this.squatSlowFilter.filter(raw, now);
    const angle = landmarkOk ? filtered : raw;
    const span = info.bodySpan ?? 0;
    const hipDepth = info.depth;

    let hint = info.hint;
    if (!landmarkOk) {
      hint = 'Отойди — стопы и колени полностью в кадре';
      this.downFrames = Math.max(0, this.downFrames - 1);
      this.upFrames = Math.max(0, this.upFrames - 1);
      this.squatStandHold = 0;
      this.opts.onPhase(this.phase, {
        ...info,
        angle,
        hint,
        angleOkDown: false,
        angleOkUp: false,
        debugLine: `${Math.round(angle)}° · ноги?`
      });
      return;
    }

    // Stable standing lock (don't chase walking noise)
    const clearlyUp = angle >= 152 && hipDepth < 0.05;
    if (clearlyUp && !this.squatSawBottom) {
      this.squatStandHold += 1;
      if (this.squatStandHold >= 4) {
        this.squatTop = Math.min(178, this.squatTop * 0.85 + angle * 0.15);
        if (span > 0.05) {
          this.squatStandSpan =
            this.squatStandSpan > 0.05
              ? this.squatStandSpan * 0.85 + span * 0.15
              : span;
        }
        this.squatApproachReject = false;
      }
    } else if (!clearlyUp) {
      this.squatStandHold = 0;
    }

    const standSpan = this.squatStandSpan > 0.05 ? this.squatStandSpan : span;
    const spanRatio = standSpan > 0.05 && span > 0.05 ? span / standSpan : 1;
    // Walking closer → body grows in frame. Real squat compresses or stays similar.
    const approaching = spanRatio > 1.14;

    // Bottom: absolute knee bend — never count approach-only motion
    const atBottom = angle <= 112 && hipDepth >= -0.05 && !approaching;

    const standing = clearlyUp && angle >= 150;

    // Cancel unfinished squat if person walks closer with fairly straight legs
    if (approaching && angle > 125) {
      this.squatSawBottom = false;
      this.squatMinAngle = 180;
      this.squatBottomHold = 0;
      this.downFrames = 0;
      this.squatApproachReject = true;
      hint = 'Не подходи ближе — стой на месте и приседай';
      this.opts.onPhase(this.phase, {
        ...info,
        angle,
        hint,
        angleOkDown: false,
        angleOkUp: standing,
        debugLine: `${Math.round(angle)}° · дистанция`
      });
      return;
    }

    if (atBottom) {
      this.downFrames += 1;
      this.upFrames = 0;
      this.squatMinAngle = Math.min(this.squatMinAngle, angle);
      this.squatBottomHold += 1;
      if (this.downFrames === 1) this.squatSpanAtDown = span;
      // Need a clear hold at the bottom so walk-by flicker doesn't count
      if (this.downFrames >= 3 && this.squatBottomHold >= 3) {
        this.squatSawBottom = true;
        this.squatApproachReject = false;
        if (this.phase !== 'down') this.phase = 'down';
        hint = 'Низ ✓ — встань';
      } else {
        hint = 'Держи низ…';
      }
      this.opts.onPhase(this.phase, {
        ...info,
        angle,
        hint,
        angleOkDown: this.squatSawBottom,
        debugLine: `${Math.round(angle)}° · низ`
      });
      return;
    }

    if (standing) {
      this.upFrames += 1;
      this.downFrames = 0;
      this.squatBottomHold = 0;
      if (this.upFrames >= 3) {
        if (
          this.squatSawBottom &&
          this.phase === 'down' &&
          !this.squatApproachReject &&
          now - this.lastRepAt > 500
        ) {
          const drop = this.squatTop - this.squatMinAngle;
          const deep = this.squatMinAngle <= 112;
          const enoughRom = drop >= 38;
          // Span must not have grown like a walk-in during the rep
          const spanOk =
            this.squatSpanAtDown <= 0.05 ||
            standSpan <= 0.05 ||
            this.squatSpanAtDown / standSpan <= 1.12;
          if (deep && enoughRom && spanOk) {
            this.reps += 1;
            this.lastRepAt = now;
            this.opts.onRep(this.reps);
          }
          this.squatSawBottom = false;
          this.squatMinAngle = 180;
          this.squatSpanAtDown = 0;
        }
        if (this.phase !== 'up') this.phase = 'up';
        hint = 'Стойка — можно садиться';
      }
      this.opts.onPhase(this.phase, {
        ...info,
        angle,
        hint,
        angleOkUp: true,
        debugLine: `${Math.round(angle)}° · верх`
      });
      return;
    }

    if (this.downFrames > 0) this.downFrames -= 1;
    if (this.upFrames > 0) this.upFrames -= 1;
    hint = this.squatSawBottom ? 'Встань полностью' : 'Присядь глубже — согни колени';
    this.opts.onPhase(this.phase, {
      ...info,
      angle,
      hint,
      debugLine: `${Math.round(angle)}°`
    });
  }

  /**
   * Single-path face-on push-up counter.
   * Primary: relative ROM (personal top − valley).
   * Confirm: ≥1 solid 2D proxy (elbow level / descent / wrist shrink) — OR, not AND-of-2.
   * Absolute valley is advisory only (unreliable across people on front camera).
   */
  private applyPushupMachine(info: RepPhaseInfo): void {
    this.pushFramesSinceRep += 1;

    const gates = pushupGates(this.pushStrictness);
    const inPlank = info.poseOk === true;
    const angleDown = info.angle;
    const angleUp = info.armAngleUp ?? info.angle;
    const elbowDrop = info.depth;
    const now = performance.now();

    // One reactive filter (no competing slow/fast acceptance paths).
    this.pushAngleFast = this.pushFastFilter.filter(angleDown, now);
    this.pushAngleEma = this.pushAngleFast;

    const dbg = (
      bend: number,
      proxies: number,
      valley: number,
      extra = ''
    ): string => {
      const vMark = valley <= GOUP_VALLEY_MAX_ANGLE ? '✓' : '~';
      return `∠${Math.round(this.pushAngleEma)}° · сгиб ${Math.round(bend)}°/${gates.minBend}° · прокси ${proxies}/3 · дно ${Math.round(valley)}°${vMark}${extra}`;
    };

    if (!inPlank) {
      this.pushupPoseBadFrames += 1;
      this.pushupPlankHoldFrames = 0;
      const standingNow = info.isStanding === true;
      const badLimit = standingNow ? 1 : 8;
      if (this.pushupPoseBadFrames >= badLimit) {
        this.pushupArmed = false;
        this.pushDownFrames = 0;
        this.pushPendingRep = false;
        this.pushNeedLockout = false;
        this.pushLockoutGrace = 0;
        this.pushRepCredited = false;
        this.pushUpHoldFrames = 0;
        this.clearPushDownTracking();
        if (this.phase === 'down') this.phase = 'up';
      }
      this.opts.onPhase(this.phase, {
        ...info,
        hint: standingNow ? 'Убери телефон с рук — упор лёжа' : 'Вернись в упор лёжа',
        debugLine: dbg(0, 0, this.pushAngleEma)
      });
      return;
    }

    this.pushupPoseBadFrames = 0;
    this.pushupPlankHoldFrames += 1;
    if (!this.pushupArmed) {
      if (this.pushupPlankHoldFrames >= 4) {
        this.pushupArmed = true;
        this.phase = 'up';
        this.pushTopAngle = Math.max(angleUp, gates.upAngle);
        this.pushFastFilter.reset(this.pushTopAngle);
        this.pushAngleEma = this.pushTopAngle;
        this.pushAngleFast = this.pushTopAngle;
        this.pushDownFrames = 0;
        this.pushUpHoldFrames = 0;
      } else {
        this.opts.onPhase(this.phase, {
          ...info,
          hint: 'Упор есть — начинай',
          debugLine: dbg(0, 0, this.pushAngleEma)
        });
        return;
      }
    }

    const bendFromTop = this.pushTopAngle - this.pushAngleEma;
    const atDown =
      bendFromTop >= gates.minBend && elbowDrop >= GOUP_MIN_ELBOW_DROP;
    const atUp =
      angleUp >= gates.upAngle && elbowDrop <= GOUP_UP_ELBOW_DROP_MAX;
    const cooled =
      this.pushFramesSinceRep >= GOUP_MIN_FRAMES_BETWEEN &&
      now - this.lastRepAt >= gates.debounceMs;

    if (this.pushPendingRep && cooled) {
      this.commitPushupRep(now, angleUp, info, 'Засчитано ✓');
      return;
    }

    if (this.pushLockoutGrace > 0) this.pushLockoutGrace -= 1;

    if (this.phase === 'up' || this.phase === 'unknown') {
      if (atUp) {
        this.pushUpHoldFrames += 1;
        if (this.pushUpHoldFrames >= gates.lockoutHold) {
          const live = Math.max(angleUp, gates.upAngle);
          if (this.pushTopAngle > live + 15) {
            this.pushTopAngle = live + 5;
          } else {
            this.pushTopAngle = Math.max(this.pushTopAngle, live);
            if (angleUp >= this.pushTopAngle - 5) {
              this.pushTopAngle = this.pushTopAngle * 0.85 + live * 0.15;
            }
          }
        }
        if (this.pushNeedLockout && this.pushUpHoldFrames >= gates.lockoutHold) {
          this.pushNeedLockout = false;
          this.pushLockoutGrace = gates.lockoutGrace;
        }
      } else {
        this.pushUpHoldFrames = 0;
      }

      this.phase = 'up';
      this.pushDownFrames = 0;
      if (!this.pushPendingRep) this.clearPushDownTracking();

      const canStartDown =
        atDown &&
        !this.pushPendingRep &&
        !this.pushNeedLockout &&
        this.pushLockoutGrace <= 0;

      if (canStartDown) {
        this.beginPushupDown(info, angleDown, angleUp, gates.upAngle);
        this.opts.onPhase('down', {
          ...info,
          hint: 'Низ…',
          debugLine: dbg(bendFromTop, 0, this.pushAngleEma)
        });
        return;
      }

      const hint = this.pushPendingRep
        ? 'Засчитываем…'
        : this.pushNeedLockout
          ? 'Выжми вверх до конца'
          : bendFromTop < 6
            ? `Верх · опустись (сгиб ≥${gates.minBend}°)`
            : `Ещё ниже · сгиб ${Math.round(bendFromTop)}°`;
      this.opts.onPhase('up', {
        ...info,
        hint,
        debugLine: dbg(bendFromTop, 0, this.pushAngleEma)
      });
      return;
    }

    if (this.phase === 'down') {
      const nowDown = performance.now();
      if (this.pushAngleEma < this.pushBottomAngle) {
        this.pushBottomAngle = this.pushAngleEma;
      }
      if (angleDown < this.pushRawMin) {
        this.pushRawMin = angleDown;
      }

      const dL = (info.leftElbowY ?? this.pushElbowY0L) - this.pushElbowY0L;
      const dR = (info.rightElbowY ?? this.pushElbowY0R) - this.pushElbowY0R;
      this.pushMaxElbowDescent = Math.max(this.pushMaxElbowDescent, dL, dR);

      const width = info.elbowWidth ?? this.pushElbowWidth0;
      const lateral = info.elbowLateral ?? this.pushElbowLateral0;
      if (width > this.pushMaxElbowWidth) this.pushMaxElbowWidth = width;
      if (lateral > this.pushMaxElbowLateral) this.pushMaxElbowLateral = lateral;

      const flareRatio = info.flareRatio ?? this.pushFlareRatio0;
      if (flareRatio > this.pushMaxFlareRatio) this.pushMaxFlareRatio = flareRatio;
      const flareRatioGain = this.pushMaxFlareRatio - this.pushFlareRatio0;

      const sw = info.shoulderWristDist ?? this.pushShoulderWrist0;
      if (sw < this.pushMinShoulderWrist) this.pushMinShoulderWrist = sw;
      const wristShrink = this.pushShoulderWrist0 - this.pushMinShoulderWrist;

      const shiftL = Math.hypot(
        (info.leftWristX ?? this.pushWristX0L) - this.pushWristX0L,
        (info.leftWristY ?? this.pushWristY0L) - this.pushWristY0L
      );
      const shiftR = Math.hypot(
        (info.rightWristX ?? this.pushWristX0R) - this.pushWristX0R,
        (info.rightWristY ?? this.pushWristY0R) - this.pushWristY0R
      );
      this.pushMaxWristShift = Math.max(this.pushMaxWristShift, shiftL, shiftR);
      const wristSoft = this.pushMaxWristShift >= GOUP_WRIST_SHIFT_SOFT;
      const wristHard = this.pushMaxWristShift >= GOUP_WRIST_SHIFT_HARD;

      if (info.bodyLineKnown === true && info.bodyLineOk === false) {
        this.pushBodyLinePoor = true;
      }
      if (info.bodyLineHardFail === true) {
        this.pushBodyLineHard = true;
      }

      if (info.elbowAtDepth === true || info.upperArmHorizontal === true) {
        this.pushSawElbowAtLevel = true;
      }

      const valley = this.pushBottomAngle;
      const bendSoFar = this.pushTopAtEnter - valley;
      const valleySoftOk = valley <= GOUP_VALLEY_MAX_ANGLE;

      const flared =
        this.pushMaxElbowWidth - this.pushElbowWidth0 >= GOUP_MIN_ELBOW_FLARE ||
        this.pushMaxElbowLateral - this.pushElbowLateral0 >= GOUP_MIN_ELBOW_LATERAL_GAIN ||
        flareRatioGain >= GOUP_MIN_FLARE_RATIO_GAIN;

      let solidProxyCount = 0;
      if (this.pushSawElbowAtLevel) solidProxyCount += 1;
      if (this.pushMaxElbowDescent >= GOUP_MIN_ELBOW_DESCENT) solidProxyCount += 1;
      if (wristShrink >= GOUP_MIN_SHOULDER_WRIST_SHRINK) solidProxyCount += 1;
      // Flare can fill the single-proxy slot when elbows are the clearest face-on cue.
      if (solidProxyCount === 0 && flared) solidProxyCount = 1;

      const depthProxyOk = solidProxyCount >= gates.minProxies;
      // Relative ROM + ≥1 proxy. Absolute valley is NOT a hard gate.
      this.pushSawElbowDepth = bendSoFar >= gates.minBend && depthProxyOk;

      if (this.pushSawElbowDepth && this.pushDepthReachedAt <= 0) {
        this.pushDepthReachedAt = nowDown;
      }

      this.pushDownFrames += 1;

      const rise = this.pushAngleEma - this.pushBottomAngle;
      const riseRaw = angleDown - this.pushRawMin;

      if (
        this.pushBottomDwellMs <= 0 &&
        this.pushDepthReachedAt > 0 &&
        (rise >= 3 || riseRaw >= 3)
      ) {
        this.pushBottomDwellMs = nowDown - this.pushDepthReachedAt;
      }

      const armsSym = pushupArmsSymmetric(
        this.pushTopAtEnter,
        info.leftArmAngle ?? angleDown,
        info.rightArmAngle ?? angleDown,
        info.leftArmOk !== false,
        info.rightArmOk !== false
      );

      const downMs = nowDown - this.pushDownStartedAt;
      const bottomDwellMs =
        this.pushBottomDwellMs > 0
          ? this.pushBottomDwellMs
          : this.pushDepthReachedAt > 0
            ? nowDown - this.pushDepthReachedAt
            : 0;
      const tempoOk =
        downMs >= GOUP_MIN_DOWN_MS &&
        (this.pushDepthReachedAt <= 0 || bottomDwellMs >= GOUP_MIN_BOTTOM_MS);

      if (wristHard && atUp && rise >= 4) {
        this.abortPushupDown(angleUp, info, 'Не засчитано — кисти на месте');
        return;
      }

      const softWristNeedsExtra = wristSoft && bendSoFar < gates.minBend + 4;
      const finished =
        atUp ||
        (angleUp >= gates.upAngle - 6 && elbowDrop <= GOUP_UP_ELBOW_DROP_MAX * 1.15);

      const formOk = !wristHard && armsSym && tempoOk;
      const countOk =
        formOk &&
        this.pushSawElbowDepth &&
        !softWristNeedsExtra &&
        bendSoFar >= gates.minBend &&
        rise >= gates.minRise &&
        this.pushDownFrames >= GOUP_MIN_DOWN_FRAMES &&
        finished;

      const debugLine = dbg(bendSoFar, solidProxyCount, valley);

      if (countOk && !this.pushRepCredited) {
        if (cooled) {
          this.commitPushupRep(now, angleUp, { ...info, debugLine }, 'Засчитано ✓');
        } else {
          this.pushRepCredited = true;
          this.pushPendingRep = true;
          this.pushNeedLockout = true;
          this.phase = 'up';
          this.pushDownFrames = 0;
          this.pushTopAngle = this.pushTopAtEnter;
          this.pushFastFilter.reset(Math.max(angleUp, this.pushTopAtEnter - 8));
          this.pushAngleEma = Math.max(this.pushAngleEma, angleUp, this.pushTopAtEnter - 8);
          this.pushAngleFast = this.pushAngleEma;
          this.clearPushDownTracking();
          this.opts.onPhase('up', {
            ...info,
            hint: 'Есть повтор — чуть подожди',
            debugLine
          });
        }
        return;
      }

      if (
        atUp &&
        bendSoFar < gates.minBend &&
        rise >= 5 &&
        !this.pushPendingRep &&
        !this.pushRepCredited
      ) {
        this.abortPushupDown(angleUp, info, 'Не засчитано — слишком мелко');
        return;
      }

      if (
        atUp &&
        rise >= 5 &&
        !this.pushSawElbowDepth &&
        !this.pushPendingRep
      ) {
        this.abortPushupDown(
          angleUp,
          info,
          solidProxyCount < gates.minProxies
            ? 'Не засчитано — ниже / локти шире'
            : 'Не засчитано — слишком мелко'
        );
        return;
      }

      if (atUp && rise >= 5 && !armsSym && !this.pushPendingRep) {
        this.abortPushupDown(angleUp, info, 'Не засчитано — обе руки');
        return;
      }

      if (
        atUp &&
        rise >= 5 &&
        !tempoOk &&
        bendSoFar >= gates.minBend &&
        !this.pushPendingRep
      ) {
        this.abortPushupDown(angleUp, info, 'Не засчитано — слишком быстро');
        return;
      }

      const bodyLineTip = this.pushBodyLineHard || this.pushBodyLinePoor;
      const hint = this.pushNeedLockout
        ? 'Выжми вверх до конца'
        : wristHard || wristSoft
          ? 'Кисти на месте'
          : !armsSym
            ? 'Обе руки одинаково'
            : bendSoFar < gates.minBend
              ? `Ниже · сгиб ${Math.round(bendSoFar)}° / ${gates.minBend}°`
              : solidProxyCount < gates.minProxies
                ? 'Ниже — локти в стороны'
                : !this.pushSawElbowDepth
                  ? 'Ниже'
                  : !tempoOk
                    ? 'Задержись чуть внизу'
                    : bodyLineTip
                      ? 'Корпус ровнее (не влияет на счёт)'
                      : !valleySoftOk
                        ? 'Можно чуть ниже'
                        : rise >= gates.minRise
                          ? 'Ещё выше — дожми'
                          : 'Выжми вверх';

      this.opts.onPhase('down', { ...info, hint, debugLine });
    }
  }

  private beginPushupDown(
    info: RepPhaseInfo,
    angleDown: number,
    angleUp: number,
    upAngle: number = GOUP_UP_ANGLE
  ): void {
    this.phase = 'down';
    this.pushRepCredited = false;
    let top = this.pushTopAngle;
    if (top > 155 && angleUp >= upAngle - 5) {
      top = Math.max(angleUp, upAngle);
    } else if (top > angleUp + 25 && angleUp >= upAngle) {
      top = Math.max(angleUp + 3, upAngle);
    }
    this.pushTopAtEnter = Math.max(upAngle, top);
    this.pushTopAngle = this.pushTopAtEnter;
    this.pushBottomAngle = this.pushAngleEma;
    this.pushRawMin = angleDown;
    this.pushDownFrames = 1;
    this.pushElbowY0L = info.leftElbowY ?? 0;
    this.pushElbowY0R = info.rightElbowY ?? 0;
    this.pushMaxElbowDescent = 0;
    this.pushSawElbowAtLevel = false;
    this.pushSawElbowDepth = false;
    this.pushElbowWidth0 = info.elbowWidth ?? 0;
    this.pushMaxElbowWidth = this.pushElbowWidth0;
    this.pushElbowLateral0 = info.elbowLateral ?? 0;
    this.pushMaxElbowLateral = this.pushElbowLateral0;
    this.pushFlareRatio0 = info.flareRatio ?? 1;
    this.pushMaxFlareRatio = this.pushFlareRatio0;
    this.pushShoulderWrist0 = info.shoulderWristDist ?? 0;
    this.pushMinShoulderWrist = this.pushShoulderWrist0;
    this.pushWristX0L = info.leftWristX ?? 0;
    this.pushWristY0L = info.leftWristY ?? 0;
    this.pushWristX0R = info.rightWristX ?? 0;
    this.pushWristY0R = info.rightWristY ?? 0;
    this.pushMaxWristShift = 0;
    this.pushDownStartedAt = performance.now();
    this.pushDepthReachedAt = 0;
    this.pushBottomDwellMs = 0;
    this.pushUpHoldFrames = 0;
    this.pushBodyLinePoor =
      info.bodyLineKnown === true && info.bodyLineOk === false;
    this.pushBodyLineHard = info.bodyLineHardFail === true;
  }
  /** Failed dip: restore locked top so slow counting stays intact. */
  private abortPushupDown(angleUp: number, info: RepPhaseInfo, hint: string): void {
    this.phase = 'up';
    this.pushDownFrames = 0;
    this.pushPendingRep = false;
    this.pushTopAngle = this.pushTopAtEnter;
    const restore = Math.max(angleUp, this.pushTopAtEnter - 5);
    this.pushSlowFilter.reset(restore);
    this.pushFastFilter.reset(restore);
    this.pushAngleEma = restore;
    this.pushAngleFast = restore;
    this.pushUpHoldFrames = 0;
    this.clearPushDownTracking();
    this.opts.onPhase('up', { ...info, hint });
  }

  private commitPushupRep(
    now: number,
    angleUp: number,
    info: RepPhaseInfo,
    hint: string
  ): void {
    if (this.pushRepCredited && !this.pushPendingRep) {
      // Already counted this cycle (direct commit after pending path reserved credit)
      this.pushPendingRep = false;
      return;
    }
    this.pushRepCredited = true;
    this.reps += 1;
    this.lastRepAt = now;
    this.pushFramesSinceRep = 0;
    this.pushPendingRep = false;
    // Must return near top before the next down can start
    this.pushNeedLockout = true;
    this.opts.onRep(this.reps);
    this.opts.onPhase('up', { ...info, hint });
    this.phase = 'up';
    this.pushDownFrames = 0;
    this.pushTopAngle = Math.max(this.pushTopAtEnter, angleUp, GOUP_UP_ANGLE);
    const seed = Math.max(angleUp, this.pushAngleEma);
    this.pushSlowFilter.reset(seed);
    this.pushFastFilter.reset(seed);
    this.pushAngleEma = seed;
    this.pushAngleFast = seed;
    this.pushUpHoldFrames = 0;
    this.clearPushDownTracking();
  }

  private clearPushDownTracking(): void {
    this.pushSawElbowDepth = false;
    this.pushSawElbowAtLevel = false;
    this.pushMaxElbowDescent = 0;
    this.pushMaxElbowWidth = 0;
    this.pushMaxElbowLateral = 0;
    this.pushMaxFlareRatio = 1;
    this.pushRawMin = 180;
    this.pushMinShoulderWrist = 1;
    this.pushBodyLinePoor = false;
    this.pushBodyLineHard = false;
    this.pushMaxWristShift = 0;
    this.pushDownStartedAt = 0;
    this.pushDepthReachedAt = 0;
    this.pushBottomDwellMs = 0;
  }

  /**
   * Crunch: dual-channel + фазы + lockout (анти-двойной счёт).
   * flat → rising → peak → lowering → flat = 1
   */
  private applyCrunchMachine(info: RepPhaseInfo): void {
    const now = performance.now();
    const minGapMs = 650;
    const LOCK_MS = 550;
    const PEAK_HOLD = 3;
    const DIR_EPS = 0.01;

    if (info.poseOk === false) {
      this.opts.onPhase(this.phase, {
        ...info,
        hint: info.hint || 'Ляг полубоком — плечи и таз в кадре'
      });
      return;
    }

    let raw = info.depth;
    if (info.depthOk === false) raw *= 0.8;
    if (info.armMode === 'swing') raw *= 0.85;

    this.crunchCurlSlow = this.crunchSlowFilter.filter(raw, now);
    this.crunchCurlFast = this.crunchFastFilter.filter(raw, now);
    const dSlow = this.crunchCurlSlow;
    const dFast = this.crunchCurlFast;
    const d = dSlow;
    const delta = dSlow - this.crunchPrevCurl;
    this.crunchPrevCurl = dSlow;
    const rising = delta >= DIR_EPS || dFast - dSlow > 0.04;
    const lowering = delta <= -DIR_EPS;

    const torsoOk = info.torsoOk === true;
    const atPeakSlow = dSlow >= CRUNCH_PEAK_ENTER && torsoOk;
    const atPeakFast =
      dFast >= CRUNCH_PEAK_ENTER - 0.06 &&
      torsoOk &&
      dSlow >= CRUNCH_PEAK_ENTER - 0.12;
    const atPeak = atPeakSlow || (atPeakFast && this.crunchStage === 'rising');
    const atFlat = dSlow <= CRUNCH_FLAT_ENTER && dFast <= CRUNCH_FLAT_ENTER + 0.06;

    const locked =
      now < this.crunchLockUntil ||
      this.crunchNeedFlatLock ||
      this.crunchRepCredited;

    if (this.crunchNeedFlatLock || this.crunchRepCredited) {
      if (atFlat && dSlow <= CRUNCH_FLAT_ENTER * 0.85) {
        this.crunchNeedFlatLock = false;
        this.crunchRepCredited = false;
        this.crunchLockUntil = 0;
        this.crunchStage = 'flat';
        this.crunchPeakHoldFrames = 0;
        this.crunchSlowFilter.reset(dSlow);
        this.crunchFastFilter.reset(dFast);
      }
    }

    if (!locked) {
      if (this.crunchStage === 'flat') {
        if ((rising || dSlow > CRUNCH_FLAT_ENTER + 0.08) && dSlow > CRUNCH_FLAT_ENTER) {
          this.crunchStage = 'rising';
          this.crunchPeakHoldFrames = 0;
        }
      } else if (this.crunchStage === 'rising') {
        if (atPeak) {
          this.crunchStage = 'peak';
          this.crunchPeakHoldFrames = 1;
        } else if (atFlat && lowering) {
          this.crunchStage = 'flat';
          this.crunchPeakHoldFrames = 0;
        }
      } else if (this.crunchStage === 'peak') {
        if (atPeakSlow || atPeakFast) {
          this.crunchPeakHoldFrames += 1;
        } else if (lowering || dSlow < CRUNCH_PEAK_ENTER - 0.08) {
          if (this.crunchPeakHoldFrames >= PEAK_HOLD) {
            this.crunchStage = 'lowering';
          } else {
            this.crunchStage = 'rising';
            this.crunchPeakHoldFrames = 0;
          }
        }
      } else if (this.crunchStage === 'lowering') {
        if (
          atFlat &&
          this.crunchPeakHoldFrames >= PEAK_HOLD &&
          !this.crunchRepCredited &&
          now - this.lastRepAt >= minGapMs
        ) {
          this.crunchRepCredited = true;
          this.reps += 1;
          this.lastRepAt = now;
          this.opts.onRep(this.reps);
          this.crunchStage = 'flat';
          this.crunchPeakHoldFrames = 0;
          this.crunchNeedFlatLock = true;
          this.crunchLockUntil = now + LOCK_MS;
          this.phase = 'up';
          this.opts.onPhase('up', {
            ...info,
            hint: 'Засчитано ✓ — ляг ровно перед следующим',
            depth: d
          });
          return;
        }
        if (atPeak && rising) {
          this.crunchStage = 'peak';
        }
      }
    }

    if (this.crunchStage === 'peak' || this.crunchStage === 'rising') {
      this.phase = 'down';
    } else {
      this.phase = 'up';
    }

    let hint = info.hint;
    if (locked && !atFlat) {
      hint = 'Ляг на лопатки до конца';
    } else if (locked) {
      hint = 'Пауза — следующий подъём';
    } else if (this.crunchStage === 'rising') {
      hint = !torsoOk ? 'Выше плечи над тазом' : 'Подъём…';
    } else if (this.crunchStage === 'peak') {
      hint = 'Верх ✓ — опускайся';
    } else if (this.crunchStage === 'lowering') {
      hint = 'Опускайся до конца — засчитаем';
    }

    this.opts.onPhase(this.phase, { ...info, hint, depth: d });
  }

  private clearCanvas(): void {
    if (!this.canvas) return;
    const prepared = this.prepareCanvas();
    if (!prepared) return;
    const { ctx, cssW, cssH } = prepared;
    ctx.clearRect(0, 0, cssW, cssH);
  }

  private prepareCanvas(): {
    ctx: CanvasRenderingContext2D;
    cssW: number;
    cssH: number;
  } | null {
    if (!this.canvas) return null;
    const canvas = this.canvas;
    const rect = canvas.getBoundingClientRect();
    const dpr = Math.max(1, window.devicePixelRatio || 1);
    const cssW = Math.max(1, Math.round(rect.width));
    const cssH = Math.max(1, Math.round(rect.height));
    if (canvas.width !== cssW * dpr || canvas.height !== cssH * dpr) {
      canvas.width = cssW * dpr;
      canvas.height = cssH * dpr;
    }
    const ctx = canvas.getContext('2d');
    if (!ctx) return null;
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
    return { ctx, cssW, cssH };
  }

  private drawPose(lm: NormalizedLandmark[]): void {
    const prepared = this.prepareCanvas();
    if (!prepared) return;
    const { ctx, cssW, cssH } = prepared;
    ctx.clearRect(0, 0, cssW, cssH);

    const vw = this.video?.videoWidth ?? 0;
    const vh = this.video?.videoHeight ?? 0;
    const wrap = this.canvas?.parentElement as HTMLElement | null;
    const fit =
      vw > 1 && vh > 1
        ? computeVideoFitLayout(vw, vh, cssW, cssH, fitModeFromWrap(wrap))
        : null;
    const toXY = (p: { x: number; y: number }) =>
      fit ? mapNormToCover(p.x, p.y, fit) : { x: p.x * cssW, y: p.y * cssH };
    const ex = this.opts.exercise;
    const isPushup = ex === 'pushup';
    const connections = isPushup ? PUSHUP_CONNECTIONS : POSE_CONNECTIONS;

    ctx.lineWidth = 3;
    ctx.lineCap = 'round';
    for (const [a, b] of connections) {
      if (!lm[a] || !lm[b]) continue;
      const pa = toXY(lm[a]);
      const pb = toXY(lm[b]);
      ctx.strokeStyle = '#38bdf8';
      ctx.beginPath();
      ctx.moveTo(pa.x, pa.y);
      ctx.lineTo(pb.x, pb.y);
      ctx.stroke();
    }

    if (isPushup) {
      for (const i of PUSHUP_POINTS) {
        if (!lm[i]) continue;
        const p = toXY(lm[i]);
        ctx.beginPath();
        ctx.fillStyle = '#fbbf24';
        ctx.arc(p.x, p.y, 6, 0, Math.PI * 2);
        ctx.fill();
      }
      return;
    }

    for (let i = 0; i < lm.length; i++) {
      const p = toXY(lm[i]);
      ctx.beginPath();
      ctx.fillStyle = HIGHLIGHT.has(i) ? '#fbbf24' : '#4ade80';
      ctx.arc(p.x, p.y, HIGHLIGHT.has(i) ? 6 : 3.5, 0, Math.PI * 2);
      ctx.fill();
    }

    ctx.setLineDash([6, 5]);
    ctx.lineWidth = 2;
    if (ex === 'squat') {
      this.drawKneeGuides(ctx, lm, toXY);
    } else if (ex === 'crunch') {
      this.drawCrunchGuides(ctx, lm, toXY);
    } else if (ex === 'burpee') {
      this.drawBurpeeGuides(ctx, lm, toXY);
    }
    ctx.setLineDash([]);
  }

  private drawKneeGuides(
    ctx: CanvasRenderingContext2D,
    lm: NormalizedLandmark[],
    toXY: (p: { x: number; y: number }) => { x: number; y: number }
  ): void {
    for (const [h, k] of [
      [23, 25],
      [24, 26]
    ] as const) {
      const H = toXY(lm[h]);
      const K = toXY(lm[k]);
      const ok = lm[h].y >= lm[k].y - 0.02;
      ctx.strokeStyle = ok ? 'rgba(34,211,238,0.9)' : 'rgba(248,113,113,0.75)';
      ctx.beginPath();
      ctx.moveTo(Math.min(H.x, K.x) - 24, K.y);
      ctx.lineTo(Math.max(H.x, K.x) + 24, K.y);
      ctx.stroke();
      const ang = angleDeg(lm[h].x, lm[h].y, lm[k].x, lm[k].y, lm[k === 25 ? 27 : 28].x, lm[k === 25 ? 27 : 28].y);
      ctx.setLineDash([]);
      ctx.font = 'bold 12px Segoe UI, sans-serif';
      ctx.strokeStyle = 'rgba(0,0,0,0.75)';
      ctx.fillStyle = '#fff';
      ctx.lineWidth = 3;
      ctx.strokeText(`${Math.round(ang)}°`, K.x + 8, K.y - 8);
      ctx.fillText(`${Math.round(ang)}°`, K.x + 8, K.y - 8);
      ctx.setLineDash([6, 5]);
      ctx.lineWidth = 2;
    }
  }

  private drawCrunchGuides(
    ctx: CanvasRenderingContext2D,
    lm: NormalizedLandmark[],
    toXY: (p: { x: number; y: number }) => { x: number; y: number }
  ): void {
    const shoulder = mid(lm[11], lm[12]);
    const hip = mid(lm[23], lm[24]);
    const Sp = toXY(shoulder);
    const Hp = toXY(hip);
    const c = evaluateCrunchPose(lm, this.crunchFlat, this.crunchWristSpeed);
    const curled = c.curl >= CRUNCH_PEAK_ENTER && c.torsoOk;
    ctx.strokeStyle = curled ? 'rgba(34,211,238,0.9)' : 'rgba(248,113,113,0.75)';
    ctx.beginPath();
    ctx.moveTo(Sp.x, Sp.y);
    ctx.lineTo(Hp.x, Hp.y);
    ctx.stroke();
    ctx.setLineDash([]);
    ctx.font = 'bold 12px Segoe UI, sans-serif';
    ctx.strokeStyle = 'rgba(0,0,0,0.75)';
    ctx.fillStyle = '#fff';
    ctx.lineWidth = 3;
    const label = `${Math.round(c.curl * 100)}% · ${this.crunchStage}`;
    ctx.strokeText(label, Hp.x + 8, Hp.y - 8);
    ctx.fillText(label, Hp.x + 8, Hp.y - 8);
    ctx.setLineDash([6, 5]);
    ctx.lineWidth = 2;
  }

  private drawBurpeeGuides(
    ctx: CanvasRenderingContext2D,
    lm: NormalizedLandmark[],
    toXY: (p: { x: number; y: number }) => { x: number; y: number }
  ): void {
    const shoulder = mid(lm[11], lm[12]);
    const hip = mid(lm[23], lm[24]);
    const Sp = toXY(shoulder);
    const Hp = toXY(hip);
    const flat = Math.abs(shoulder.y - hip.y) < 0.12;
    ctx.strokeStyle = flat ? 'rgba(34,211,238,0.9)' : 'rgba(251,191,36,0.85)';
    ctx.beginPath();
    ctx.moveTo(Sp.x, Sp.y);
    ctx.lineTo(Hp.x, Hp.y);
    ctx.stroke();
    ctx.setLineDash([]);
    ctx.font = 'bold 12px Segoe UI, sans-serif';
    ctx.fillStyle = '#fff';
    ctx.strokeStyle = 'rgba(0,0,0,0.75)';
    ctx.lineWidth = 3;
    const t = flat ? 'планка' : 'стойка/переход';
    ctx.strokeText(t, Hp.x + 8, Hp.y - 8);
    ctx.fillText(t, Hp.x + 8, Hp.y - 8);
    ctx.setLineDash([6, 5]);
    ctx.lineWidth = 2;
  }
}
