/** Прогресс арены и профиль (localStorage). SQL — только после аккаунта. */

import {
  LEVELS,
  LEGACY_TIER_LEVEL_IDS,
  levelsForTier,
  type LevelId,
  type TierId
} from './levels';
import type { ChallengeId } from './challenges';

const KEY = 'legion-arena-progress-v1';
const PROFILE_KEY = 'legion-arena-profile-v1';
const MIGRATED_KEY = 'legion-arena-progress-tier10-v1';

export interface LevelClear {
  clearedAt: string;
  totalReps: number;
  exercise: string;
}

export interface ChallengeBest {
  clearedAt: string;
  /** Время прохождения в мс (меньше = лучше) — для timed */
  timeMs: number;
  exercise: string;
  targetReps: number;
  /** Для endurance — лучший результат по повторам (больше = лучше) */
  bestReps?: number;
}

export interface ArenaProgress {
  levels: Partial<Record<LevelId, LevelClear>>;
  challenges: Partial<Record<ChallengeId, ChallengeBest>>;
}

export interface AthleteProfile {
  name: string;
  /** YYYY-MM-DD of last training day */
  lastActiveDay: string;
  /** Consecutive active days */
  streakDays: number;
  /** Lifetime counted reps across fights */
  lifetimeReps: number;
}

function empty(): ArenaProgress {
  return { levels: {}, challenges: {} };
}

function emptyProfile(): AthleteProfile {
  return {
    name: '',
    lastActiveDay: '',
    streakDays: 0,
    lifetimeReps: 0
  };
}

function todayKey(): string {
  const d = new Date();
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  return `${y}-${m}-${day}`;
}

function dayOffset(isoDay: string, delta: number): string {
  const [y, m, d] = isoDay.split('-').map(Number);
  const dt = new Date(y!, m! - 1, d!);
  dt.setDate(dt.getDate() + delta);
  const yy = dt.getFullYear();
  const mm = String(dt.getMonth() + 1).padStart(2, '0');
  const dd = String(dt.getDate()).padStart(2, '0');
  return `${yy}-${mm}-${dd}`;
}

function expandLegacyTier(progress: ArenaProgress): { progress: ArenaProgress; changed: boolean } {
  let changed = false;
  const levels = { ...progress.levels };
  for (const tierId of LEGACY_TIER_LEVEL_IDS) {
    const legacy = levels[tierId];
    if (!legacy) continue;
    for (const level of levelsForTier(tierId as TierId)) {
      const prev = levels[level.id];
      if (!prev || legacy.totalReps > prev.totalReps) {
        levels[level.id] = {
          clearedAt: legacy.clearedAt,
          totalReps: Math.max(prev?.totalReps ?? 0, legacy.totalReps),
          exercise: legacy.exercise || prev?.exercise || 'pushup'
        };
        changed = true;
      }
    }
    delete levels[tierId];
    changed = true;
  }
  return { progress: { ...progress, levels }, changed };
}

function migrateLegacyTierClears(progress: ArenaProgress): ArenaProgress {
  const { progress: next, changed } = expandLegacyTier(progress);
  if (changed) saveProgress(next);
  try {
    localStorage.setItem(MIGRATED_KEY, '1');
  } catch {
    /* ignore */
  }
  return next;
}

export function loadProgress(): ArenaProgress {
  try {
    const raw = localStorage.getItem(KEY);
    if (!raw) return empty();
    const parsed = JSON.parse(raw) as ArenaProgress;
    const base: ArenaProgress = {
      levels: parsed.levels ?? {},
      challenges: parsed.challenges ?? {}
    };
    return migrateLegacyTierClears(base);
  } catch {
    return empty();
  }
}

export function saveProgress(progress: ArenaProgress): void {
  localStorage.setItem(KEY, JSON.stringify(progress));
}

export function loadProfile(): AthleteProfile {
  try {
    const raw = localStorage.getItem(PROFILE_KEY);
    if (!raw) return emptyProfile();
    const parsed = JSON.parse(raw) as AthleteProfile;
    return {
      name: typeof parsed.name === 'string' ? parsed.name.slice(0, 40) : '',
      lastActiveDay: parsed.lastActiveDay || '',
      streakDays: Number(parsed.streakDays) || 0,
      lifetimeReps: Number(parsed.lifetimeReps) || 0
    };
  } catch {
    return emptyProfile();
  }
}

export function saveProfile(profile: AthleteProfile): void {
  localStorage.setItem(PROFILE_KEY, JSON.stringify(profile));
}

export function setAthleteName(name: string): AthleteProfile {
  const profile = loadProfile();
  profile.name = name.trim().slice(0, 40);
  saveProfile(profile);
  return profile;
}

/** Call when a rep is counted in a real fight. Updates streak + lifetime. */
export function recordActivityRep(count = 1): AthleteProfile {
  const profile = loadProfile();
  const today = todayKey();
  if (profile.lastActiveDay !== today) {
    if (profile.lastActiveDay && profile.lastActiveDay === dayOffset(today, -1)) {
      profile.streakDays = Math.max(1, profile.streakDays) + 1;
    } else {
      profile.streakDays = 1;
    }
    profile.lastActiveDay = today;
  } else if (profile.streakDays < 1) {
    profile.streakDays = 1;
  }
  profile.lifetimeReps += Math.max(0, count);
  saveProfile(profile);
  return profile;
}

export function markLevelCleared(
  levelId: LevelId,
  totalReps: number,
  exercise: string
): ArenaProgress {
  const progress = loadProgress();
  const prev = progress.levels[levelId];
  progress.levels[levelId] = {
    clearedAt: new Date().toISOString(),
    totalReps: prev ? Math.max(prev.totalReps, totalReps) : totalReps,
    exercise
  };
  saveProgress(progress);
  return progress;
}

export function markChallengeBest(
  challengeId: ChallengeId,
  timeMs: number,
  targetReps: number,
  exercise: string,
  bestReps?: number
): ArenaProgress {
  const progress = loadProgress();
  const prev = progress.challenges[challengeId];
  const isEndurance = typeof bestReps === 'number';
  if (isEndurance) {
    if (!prev || (prev.bestReps ?? 0) < bestReps!) {
      progress.challenges[challengeId] = {
        clearedAt: new Date().toISOString(),
        timeMs,
        targetReps: bestReps!,
        exercise,
        bestReps
      };
      saveProgress(progress);
    }
  } else if (!prev || timeMs < prev.timeMs) {
    progress.challenges[challengeId] = {
      clearedAt: new Date().toISOString(),
      timeMs,
      targetReps,
      exercise
    };
    saveProgress(progress);
  }
  return progress;
}

export function isLevelCleared(levelId: LevelId): boolean {
  return Boolean(loadProgress().levels[levelId]);
}

export function clearedLevelCount(): number {
  const progress = loadProgress();
  return LEVELS.filter((l) => Boolean(progress.levels[l.id])).length;
}

/** Открыт, если все предыдущие уровни кампании пройдены. */
export function isLevelUnlocked(levelId: LevelId): boolean {
  const idx = LEVELS.findIndex((l) => l.id === levelId);
  if (idx < 0) return false;
  if (idx === 0) return true;
  const progress = loadProgress();
  for (let i = 0; i < idx; i++) {
    if (!progress.levels[LEVELS[i]!.id]) return false;
  }
  return true;
}

/** Первый непройденный уровень кампании. */
export function currentCampaignLevelId(): LevelId | null {
  const progress = loadProgress();
  for (const level of LEVELS) {
    if (!progress.levels[level.id]) return level.id;
  }
  return null;
}

export function nextLockedLevelId(): LevelId | null {
  return currentCampaignLevelId();
}

/** Слияние серверного прогресса с локальным (берём лучшее). */
export function mergeServerProgress(server: {
  levels?: ArenaProgress['levels'];
  challenges?: ArenaProgress['challenges'];
}): ArenaProgress {
  const local = loadProgress();
  const levels = { ...local.levels };
  for (const [id, clear] of Object.entries(server.levels || {})) {
    if (!clear) continue;
    const key = id as LevelId;
    const prev = levels[key];
    if (!prev || clear.totalReps > prev.totalReps) {
      levels[key] = clear;
    }
  }
  const challenges = { ...local.challenges };
  for (const [id, best] of Object.entries(server.challenges || {})) {
    if (!best) continue;
    const key = id as ChallengeId;
    const prev = challenges[key];
    if (!prev) {
      challenges[key] = best;
      continue;
    }
    if (typeof best.bestReps === 'number') {
      if ((prev.bestReps ?? 0) < best.bestReps) challenges[key] = best;
    } else if (best.timeMs > 0 && (prev.timeMs === 0 || best.timeMs < prev.timeMs)) {
      challenges[key] = best;
    }
  }
  const { progress: merged } = expandLegacyTier({ levels, challenges });
  saveProgress(merged);
  return merged;
}

export function mergeServerProfile(server: {
  displayName?: string;
  streakDays?: number;
  lifetimeReps?: number;
  lastActiveDay?: string;
}): AthleteProfile {
  const profile = loadProfile();
  if (server.displayName && !profile.name) profile.name = server.displayName.slice(0, 40);
  profile.streakDays = Math.max(profile.streakDays, Number(server.streakDays) || 0);
  profile.lifetimeReps = Math.max(profile.lifetimeReps, Number(server.lifetimeReps) || 0);
  if (server.lastActiveDay && (!profile.lastActiveDay || server.lastActiveDay >= profile.lastActiveDay)) {
    profile.lastActiveDay = server.lastActiveDay;
  }
  saveProfile(profile);
  return profile;
}

/** Пороги XP (= lifetimeReps) для уровней персонажа. */
export const PLAYER_LEVEL_THRESHOLDS = [0, 25, 60, 120, 200, 350, 550, 800, 1100, 1500];

export interface PlayerLevelInfo {
  level: number;
  xp: number;
  xpIntoLevel: number;
  xpForNext: number;
  /** 0..1 progress within current level; 1 if max */
  progress: number;
  toNext: number;
  isMax: boolean;
}

export function getPlayerLevelInfo(lifetimeReps?: number): PlayerLevelInfo {
  const xp = Math.max(0, lifetimeReps ?? loadProfile().lifetimeReps);
  const thresholds = PLAYER_LEVEL_THRESHOLDS;
  let level = 1;
  for (let i = thresholds.length - 1; i >= 0; i--) {
    if (xp >= thresholds[i]!) {
      level = i + 1;
      break;
    }
  }
  const floor = thresholds[level - 1] ?? 0;
  const next = thresholds[level];
  if (next == null) {
    return {
      level,
      xp,
      xpIntoLevel: xp - floor,
      xpForNext: 0,
      progress: 1,
      toNext: 0,
      isMax: true
    };
  }
  const span = Math.max(1, next - floor);
  const into = xp - floor;
  return {
    level,
    xp,
    xpIntoLevel: into,
    xpForNext: span,
    progress: Math.min(1, into / span),
    toNext: Math.max(0, next - xp),
    isMax: false
  };
}
