/** Кампания «Легион Силы»: 6 ступеней × 10 уровней. */

export type FoeKind = 'mob' | 'boss';

export type FoeWeakness = 'tempo' | 'depth' | 'lockout' | 'endurance';

export interface Foe {
  id: string;
  name: string;
  kind: FoeKind;
  hp: number;
  emoji: string;
  color: string;
  blurb: string;
  enterLine?: string;
  winLine?: string;
  weakness?: FoeWeakness;
  weaknessLabel?: string;
}

export type TierId =
  | 'recruit'
  | 'legionnaire'
  | 'gladiator'
  | 'centurion'
  | 'titan'
  | 'emperor';

/** Например recruit-01 … recruit-10 */
export type LevelId = string;

export interface TierDef {
  id: TierId;
  name: string;
  shortName: string;
  emoji: string;
  color: string;
  lore: string;
  blurb: string;
  banner: string;
  /** Суммарный HP (до соло-множителя) на ур. 1 / 5 / 10 */
  hpAnchors: [number, number, number];
}

export interface Level {
  id: LevelId;
  tierId: TierId;
  /** 1..10 внутри ступени */
  stageIndex: number;
  name: string;
  title: string;
  emoji: string;
  color: string;
  lore: string;
  blurb: string;
  banner: string;
  hasBoss: boolean;
  foes: Foe[];
}

