/** Старые id ступеней (до разбиения на 10 уровней). */
export const LEGACY_TIER_LEVEL_IDS: TierId[] = TIERS.map((t) => t.id);

function lerp(a: number, b: number, t: number): number {
  return a + (b - a) * t;
}

/** Суммарный базовый HP уровня (до соло-множителя). */
export function tierLevelTotalHp(tier: TierDef, stageIndex: number): number {
  const [a1, a5, a10] = tier.hpAnchors;
  if (stageIndex <= 5) {
    return Math.round(lerp(a1, a5, (stageIndex - 1) / 4));
  }
  return Math.round(lerp(a5, a10, (stageIndex - 5) / 5));
}

function splitHp(total: number, parts: number, bossLast: boolean): number[] {
  if (parts <= 1) return [Math.max(1, total)];
  const weights: number[] = [];
  for (let i = 0; i < parts; i++) {
    if (bossLast && i === parts - 1) weights.push(1.55);
    else weights.push(0.85 + i * 0.12);
  }
  const sumW = weights.reduce((s, w) => s + w, 0);
  const raw = weights.map((w) => (total * w) / sumW);
  const hp = raw.map((x) => Math.max(1, Math.round(x)));
  let diff = total - hp.reduce((s, x) => s + x, 0);
  let i = hp.length - 1;
  while (diff !== 0 && hp.length > 0) {
    const step = diff > 0 ? 1 : -1;
    if (hp[i]! + step >= 1) {
      hp[i]! += step;
      diff -= step;
    }
    i = (i - 1 + hp.length) % hp.length;
  }
  return hp;
}

function mobCountForStage(stageIndex: number, hasBoss: boolean): number {
  if (hasBoss) return stageIndex === 10 ? 3 : 2;
  if (stageIndex <= 2) return 2;
  if (stageIndex <= 7) return 3;
  return 3;
}

function buildFoes(tier: TierDef, stageIndex: number): Foe[] {
  const hasBoss = stageIndex === 5 || stageIndex === 10;
  const mobN = mobCountForStage(stageIndex, hasBoss);
  const parts = hasBoss ? mobN + 1 : mobN;
  const total = tierLevelTotalHp(tier, stageIndex);
  const hps = splitHp(total, parts, hasBoss);
  const pool = MOB_POOL[tier.id];
  const foes: Foe[] = [];

  for (let i = 0; i < mobN; i++) {
    const mob = pool[(stageIndex * 3 + i) % pool.length]!;
    const hp = hps[i]!;
    foes.push({
      id: `${tier.id}-s${stageIndex}-m${i + 1}`,
      name: `Легионер «${mob.name}»`,
      kind: 'mob',
      hp,
      emoji: mob.emoji,
      color: tier.color,
      blurb: mob.blurb,
      enterLine: `${mob.name}: держи амплитуду.`,
      winLine: `${mob.name} повержен.`
    });
  }

  if (hasBoss) {
    const bossDef = stageIndex === 5 ? BOSS_MID[tier.id] : BOSS_FINAL[tier.id];
    const hp = hps[hps.length - 1]!;
    foes.push({
      id: `${tier.id}-s${stageIndex}-boss`,
      name: bossDef.name,
      kind: 'boss',
      hp,
      emoji: bossDef.emoji,
      color: tier.color,
      blurb: 'Босс уровня',
      enterLine: `${bossDef.name}: «Покажи строй.»`,
      winLine: `${bossDef.name} пал. Путь открыт.`,
      weakness: bossDef.weakness,
      weaknessLabel: bossDef.weaknessLabel
    });
  }

  return foes;
}

function buildLevel(tier: TierDef, stageIndex: number): Level {
  const id = `${tier.id}-${String(stageIndex).padStart(2, '0')}`;
  const hasBoss = stageIndex === 5 || stageIndex === 10;
  const foes = buildFoes(tier, stageIndex);
  return {
    id,
    tierId: tier.id,
    stageIndex,
    name: `${tier.shortName} · Уровень ${stageIndex}`,
    title: `Уровень ${stageIndex}`,
    emoji: hasBoss ? foes[foes.length - 1]!.emoji : tier.emoji,
    color: tier.color,
    lore: tier.lore,
    blurb: hasBoss ? `${tier.blurb} · босс` : tier.blurb,
    banner: tier.banner,
    hasBoss,
    foes
  };
}

export const LEVELS: Level[] = TIERS.flatMap((tier) =>
  Array.from({ length: 10 }, (_, i) => buildLevel(tier, i + 1))
);

export function getTier(id: TierId): TierDef {
  const tier = TIERS.find((t) => t.id === id);
  if (!tier) throw new Error(`Unknown tier: ${id}`);
  return tier;
}

export function levelsForTier(tierId: TierId): Level[] {
  return LEVELS.filter((l) => l.tierId === tierId);
}

export function getTierIndex(tierId: TierId): number {
  return TIERS.findIndex((t) => t.id === tierId);
}

export function nextTier(tierId: TierId): TierDef | null {
  const i = getTierIndex(tierId);
  return i >= 0 ? TIERS[i + 1] ?? null : null;
}

/** Короткие реплики толпы / центуриона — каждые N повторов. */
export const ARENA_CROWD_LINES = [
  'Толпа: «Держи амплитуду!»',
  'Центурион: «Строй не дрожит.»',
  'Толпа: «Ещё! Легион смотрит.»',
  'Центурион: «Локти в работу.»',
  'Толпа: «Это сила Легиона!»',
  'Центурион: «Не рви темп — веди его.»',
  'Толпа: «Знамя близко!»',
  'Центурион: «Дыши. Жми. Снова.»'
];

export function crowdLineForRep(repTotal: number): string | null {
  if (repTotal <= 0 || repTotal % 5 !== 0) return null;
  const i = (Math.floor(repTotal / 5) - 1) % ARENA_CROWD_LINES.length;
  return ARENA_CROWD_LINES[i] ?? null;
}

export function getLevel(id: LevelId): Level {
  const level = LEVELS.find((l) => l.id === id);
  if (!level) throw new Error(`Unknown level: ${id}`);
  return level;
}

export function levelTotalHp(level: Level): number {
  return level.foes.reduce((sum, f) => sum + f.hp, 0);
}

/** Соло-режим: меньше HP, чем в клановых рейдах. */
export const SOLO_HP_MULT = 0.65;

export function soloHp(baseHp: number): number {
  return Math.max(1, Math.round(baseHp * SOLO_HP_MULT));
}

export function scaleFoeSolo(foe: Foe): Foe {
  return { ...foe, hp: soloHp(foe.hp) };
}

export function levelTotalHpSolo(level: Level): number {
  return level.foes.reduce((sum, f) => sum + soloHp(f.hp), 0);
}

export function levelMobCount(level: Level): number {
  return level.foes.filter((f) => f.kind === 'mob').length;
}

export function getFoe(level: Level, index: number): Foe {
  const foe = level.foes[index];
  if (!foe) throw new Error(`No foe at index ${index}`);
  return foe;
}

export function isTierCleared(
  tierId: TierId,
  cleared: Partial<Record<string, unknown>>
): boolean {
  return levelsForTier(tierId).every((l) => Boolean(cleared[l.id]));
}

export function clearedTierCount(cleared: Partial<Record<string, unknown>>): number {
  return TIERS.filter((t) => isTierCleared(t.id, cleared)).length;
}
