export type ExerciseId = 'pushup' | 'squat' | 'crunch' | 'burpee';

export interface ExerciseDef {
  id: ExerciseId;
  name: string;
  emoji: string;
  short: string;
  /** One short line: how to take the start pose */
  poseHow: string;
  cameraTitle: string;
  cameraTips: string[];
  repLabel: string;
}

export const EXERCISES: ExerciseDef[] = [
  {
    id: 'pushup',
    name: 'Отжимания',
    emoji: '💪',
    short: 'Отжимания',
    poseHow: 'Упор лёжа · лицо к телефону · локти и кисти в кадре',
    cameraTitle: 'Отжимания',
    cameraTips: [
      'Телефон на полу перед собой.',
      'Упор лёжа лицом к камере.',
      'В кадре: плечи, локти, кисти.'
    ],
    repLabel: 'Отжимания'
  },
  {
    id: 'squat',
    name: 'Приседания',
    emoji: '🦵',
    short: 'Приседания',
    poseHow: 'Встань перед телефоном · весь рост в кадре',
    cameraTitle: 'Приседания',
    cameraTips: [
      'Телефон в 2–3 м перед тобой.',
      'Лучше чуть сбоку.',
      'В кадре: голова и стопы.'
    ],
    repLabel: 'Приседания'
  }
];

export function getExercise(id: ExerciseId): ExerciseDef {
  const ex = EXERCISES.find((e) => e.id === id);
  if (!ex) throw new Error(`Unknown exercise: ${id}`);
  return ex;
}
