/** Клиент API Move Boss. Гость — localStorage; аккаунт — SQL и лидерборд. */

const AUTH_KEY = 'legion-arena-auth-v1';

export interface AuthSession {
  token: string;
  nickname: string;
}

export interface LeaderRow {
  rank: number;
  nickname: string;
  displayName: string;
  bannersCleared: number;
  challengesCleared: number;
  lifetimeReps: number;
  streakDays: number;
}

export interface ServerPlayer {
  id: number;
  nickname: string;
  displayName: string;
  streakDays: number;
  lifetimeReps: number;
  lastActiveDay: string;
  bannersCleared: number;
  challengesCleared: number;
}

export interface ServerProgress {
  levels: Record<string, { clearedAt: string; totalReps: number; exercise: string }>;
  challenges: Record<
    string,
    {
      clearedAt: string;
      timeMs: number;
      targetReps: number;
      exercise: string;
      bestReps?: number;
    }
  >;
}

function apiBase(): string {
  return '/api/events';
}

export function loadAuth(): AuthSession | null {
  try {
    const raw = localStorage.getItem(AUTH_KEY);
    if (!raw) return null;
    const parsed = JSON.parse(raw) as AuthSession;
    if (!parsed.token || !parsed.nickname) return null;
    return parsed;
  } catch {
    return null;
  }
}

export function saveAuth(session: AuthSession | null): void {
  if (!session) {
    localStorage.removeItem(AUTH_KEY);
    return;
  }
  localStorage.setItem(AUTH_KEY, JSON.stringify(session));
}

async function postJson<T>(path: string, body: unknown): Promise<T> {
  const res = await fetch(apiBase() + path, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(body)
  });
  const data = (await res.json().catch(() => ({}))) as T & { error?: string };
  if (!res.ok) throw new Error(data.error || `Ошибка ${res.status}`);
  return data;
}

async function getJson<T>(path: string): Promise<T> {
  const res = await fetch(apiBase() + path);
  const data = (await res.json().catch(() => ({}))) as T & { error?: string };
  if (!res.ok) throw new Error(data.error || `Ошибка ${res.status}`);
  return data;
}

export async function registerAccount(input: {
  nickname: string;
  password: string;
  displayName?: string;
  profile: unknown;
  progress: unknown;
}): Promise<{ token: string; player: ServerPlayer; progress: ServerProgress }> {
  const data = await postJson<{
    token: string;
    player: ServerPlayer;
    progress: ServerProgress;
  }>('/register.php', input);
  saveAuth({ token: data.token, nickname: data.player.nickname });
  return data;
}

export async function loginAccount(input: {
  nickname: string;
  password: string;
  profile: unknown;
  progress: unknown;
}): Promise<{ token: string; player: ServerPlayer; progress: ServerProgress }> {
  const data = await postJson<{
    token: string;
    player: ServerPlayer;
    progress: ServerProgress;
  }>('/login.php', input);
  saveAuth({ token: data.token, nickname: data.player.nickname });
  return data;
}

export async function logoutAccount(): Promise<void> {
  const auth = loadAuth();
  if (auth) {
    try {
      await postJson('/logout.php', { token: auth.token });
    } catch {
      /* ignore */
    }
  }
  saveAuth(null);
}

export async function syncToServer(input: {
  profile: unknown;
  progress: unknown;
  run?: {
    kind: 'arena' | 'challenge';
    refId: string;
    reps: number;
    durationMs?: number;
    exercise: string;
    completed: boolean;
  };
}): Promise<{ player: ServerPlayer; progress: ServerProgress } | null> {
  const auth = loadAuth();
  if (!auth) return null;
  try {
    return await postJson('/sync.php', { token: auth.token, ...input });
  } catch {
    return null;
  }
}

/** GET прогресса с сервера (для hydrate при старте). */
export async function fetchProgress(): Promise<{
  player: ServerPlayer;
  progress: ServerProgress;
} | null> {
  const auth = loadAuth();
  if (!auth) return null;
  try {
    return await getJson(`/progress.php?token=${encodeURIComponent(auth.token)}`);
  } catch {
    return null;
  }
}

/** POST прогресса без лога попытки. */
export async function pushProgress(input: {
  profile: unknown;
  progress: unknown;
}): Promise<{ player: ServerPlayer; progress: ServerProgress } | null> {
  const auth = loadAuth();
  if (!auth) return null;
  try {
    return await postJson('/progress.php', { token: auth.token, ...input });
  } catch {
    return null;
  }
}

/** POST лога одной попытки. */
export async function logResult(input: {
  kind: 'arena' | 'challenge';
  refId: string;
  reps: number;
  durationMs?: number;
  exercise: string;
  completed: boolean;
}): Promise<boolean> {
  const auth = loadAuth();
  if (!auth) return false;
  try {
    await postJson('/result.php', { token: auth.token, ...input });
    return true;
  } catch {
    return false;
  }
}

export async function fetchLeaderboard(limit = 30): Promise<LeaderRow[]> {
  const data = await getJson<{ leaders: LeaderRow[] }>(`/leaderboard.php?limit=${limit}`);
  return data.leaders || [];
}
