import type { ExerciseId } from './exercises';
import { crunchHalfSideOriented, evaluateCrunchPose } from './crunchPose';
import { evaluatePushupPose } from './pushupPose';

export interface SetupCheck {
  id: string;
  label: string;
  ok: boolean;
}

export interface SetupResult {
  ready: boolean;
  bodyFound: boolean;
  checks: SetupCheck[];
  hint: string;
}

type Lm = { x: number; y: number; visibility?: number };

function mid(a: Lm, b: Lm): Lm {
  return { x: (a.x + b.x) / 2, y: (a.y + b.y) / 2 };
}

function angleDeg(ax: number, ay: number, bx: number, by: number, cx: number, cy: number): number {
  const v1x = ax - bx;
  const v1y = ay - by;
  const v2x = cx - bx;
  const v2y = cy - by;
  const dot = v1x * v2x + v1y * v2y;
  const n1 = Math.hypot(v1x, v1y);
  const n2 = Math.hypot(v2x, v2y);
  if (n1 < 1e-6 || n2 < 1e-6) return 180;
  const cos = Math.min(1, Math.max(-1, dot / (n1 * n2)));
  return (Math.acos(cos) * 180) / Math.PI;
}

function conf(lm: Lm | undefined): number {
  if (!lm || !Number.isFinite(lm.x) || !Number.isFinite(lm.y)) return 0;
  return typeof lm.visibility === 'number' ? lm.visibility : 0.55;
}

function visible(lm: Lm[] | undefined, idxs: number[]): boolean {
  if (!lm || lm.length < 29) return false;
  return idxs.every((i) => lm[i] && Number.isFinite(lm[i].x) && Number.isFinite(lm[i].y));
}

function visibleConfident(lm: Lm[] | undefined, idxs: number[], min = 0.35): boolean {
  if (!lm || lm.length < 29) return false;
  return idxs.every((i) => conf(lm[i]) >= min);
}

/** Live camera framing check before the fight starts */
export function evaluateCameraSetup(exercise: ExerciseId, lm: Lm[] | undefined): SetupResult {
  const bodyFound = visible(lm, [11, 12, 23, 24]);
  if (!bodyFound || !lm) {
    return {
      ready: false,
      bodyFound: false,
      checks: [{ id: 'body', label: 'Тело в кадре', ok: false }],
      hint: 'Встань в кадр — нужны точки на теле'
    };
  }

  const shoulder = mid(lm[11], lm[12]);
  const hip = mid(lm[23], lm[24]);
  const ankle = mid(lm[27], lm[28]);
  const lKnee = angleDeg(lm[23].x, lm[23].y, lm[25].x, lm[25].y, lm[27].x, lm[27].y);
  const rKnee = angleDeg(lm[24].x, lm[24].y, lm[26].x, lm[26].y, lm[28].x, lm[28].y);
  const kneeAngle = Math.min(lKnee, rKnee);
  const torsoDrop = hip.y - shoulder.y;

  let checks: SetupCheck[] = [];
  let hint = '';

  switch (exercise) {
    case 'pushup': {
      const armsOk =
        visible(lm, [13, 14, 15, 16]) ||
        visible(lm, [11, 13, 15]) ||
        visible(lm, [12, 14, 16]);
      const p = evaluatePushupPose(lm);
      checks = [
        { id: 'body', label: 'Тело в кадре', ok: true },
        { id: 'arms', label: 'Плечи и локти в кадре', ok: armsOk },
        { id: 'plank', label: 'Упор лёжа', ok: p.inPlank }
      ];
      hint = !armsOk
        ? 'Ближе телефон — локти в кадр'
        : !p.inPlank
          ? p.hintSetup
          : 'Готово — не двигайся';
      break;
    }
    case 'squat': {
      const legsConfident =
        visibleConfident(lm, [23, 25, 27], 0.32) || visibleConfident(lm, [24, 26, 28], 0.32);
      const fullBody =
        (visibleConfident(lm, [0, 23, 24], 0.3) || visibleConfident(lm, [11, 12, 23, 24], 0.3)) &&
        legsConfident;
      const standing = torsoDrop > 0.06 && kneeAngle > 130;
      const room =
        ankle.y > 0.58 &&
        ankle.y < 0.98 &&
        shoulder.y > 0.04 &&
        shoulder.y < 0.52;
      checks = [
        { id: 'body', label: 'Весь рост в кадре', ok: fullBody && room },
        { id: 'stand', label: 'Стой ровно', ok: standing },
        { id: 'legs', label: 'Видны ноги и стопы', ok: legsConfident }
      ];
      hint = !fullBody || !room
        ? 'Отойди — голова и стопы в кадре (без обрезки)'
        : !legsConfident
          ? 'Стопы видны плохо — дальше от телефона'
          : !standing
            ? 'Встань ровно перед камерой'
            : 'Готово — не двигайся';
      break;
    }
    case 'crunch': {
      const feetToward = crunchHalfSideOriented(lm);
      const p = evaluateCrunchPose(lm);
      const lying =
        Math.abs(shoulder.y - hip.y) < 0.35 ||
        (Math.abs(shoulder.x - hip.x) > 0.08 && Math.abs(shoulder.y - hip.y) < 0.4);
      const legsOk =
        visible(lm, [23, 24, 25, 26]) ||
        visible(lm, [25, 26, 27, 28]) ||
        visible(lm, [23, 24, 27, 28]);
      const sideOk =
        Math.abs(shoulder.x - (lm[25]?.x ?? lm[27]?.x ?? shoulder.x)) > 0.12 ||
        Math.abs(hip.x - (lm[25]?.x ?? hip.x)) > 0.1;
      const armsCalm = p.armMode !== 'swing';
      checks = [
        { id: 'body', label: 'Тело в кадре', ok: true },
        { id: 'side', label: 'Полубоком к телефону', ok: feetToward && sideOk },
        {
          id: 'lie',
          label: p.kneesBent ? 'Лёжа (колени согнуты)' : 'Лёжа на спине',
          ok: lying && legsOk
        },
        { id: 'arms', label: 'Руки спокойно', ok: armsCalm }
      ];
      hint = !feetToward || !sideOk
        ? 'Ляг полубоком — телефон сбоку, видны плечо–таз–колено'
        : !lying || !legsOk
          ? 'Ляг на спину · колени согнуты или прямые'
          : !armsCalm
            ? 'Убери взмах — руки на груди или за головой'
            : 'Готово — не двигайся (калибруем «лёжа»)';
      break;
    }
    case 'burpee':
    default: {
      const fullBody = ankle.y > 0.55 && shoulder.y < 0.5;
      const standing = torsoDrop > 0.06 && kneeAngle > 125;
      checks = [
        { id: 'body', label: 'Весь рост в кадре', ok: fullBody },
        { id: 'stand', label: 'Стой ровно', ok: standing },
        { id: 'space', label: 'Место сверху и снизу', ok: shoulder.y > 0.05 && ankle.y < 0.98 }
      ];
      hint = !fullBody
        ? 'Отойди — нужен весь рост'
        : !standing
          ? 'Встань ровно'
          : 'Готово — не двигайся';
      break;
    }
  }

  const ready = checks.every((c) => c.ok);
  return { ready, bodyFound: true, checks, hint: ready ? 'Готово — не двигайся' : hint };
}
