const MUTE_KEY = 'legion-arena-mute-v1';

let ctx: AudioContext | null = null;
let muted = loadMuted();
let unlockWired = false;

function loadMuted(): boolean {
  try {
    return localStorage.getItem(MUTE_KEY) === '1';
  } catch {
    return false;
  }
}

function saveMuted(value: boolean): void {
  try {
    localStorage.setItem(MUTE_KEY, value ? '1' : '0');
  } catch {
    /* ignore */
  }
}

function getCtx(): AudioContext | null {
  const AC =
    window.AudioContext ||
    (window as unknown as { webkitAudioContext?: typeof AudioContext }).webkitAudioContext;
  if (!AC) return null;
  if (!ctx) ctx = new AC();
  return ctx;
}

async function ensureRunning(): Promise<AudioContext | null> {
  if (muted) return null;
  const c = getCtx();
  if (!c) return null;
  try {
    if (c.state === 'suspended') await c.resume();
  } catch {
    return null;
  }
  return c.state === 'running' ? c : null;
}

function tone(
  c: AudioContext,
  opts: {
    type?: OscillatorType;
    freq: number;
    freqEnd?: number;
    start: number;
    dur: number;
    peak?: number;
    attack?: number;
  }
): void {
  const osc = c.createOscillator();
  const gain = c.createGain();
  const peak = opts.peak ?? 0.22;
  const attack = opts.attack ?? 0.012;
  osc.type = opts.type ?? 'sine';
  osc.frequency.setValueAtTime(opts.freq, opts.start);
  if (opts.freqEnd != null) {
    osc.frequency.exponentialRampToValueAtTime(Math.max(40, opts.freqEnd), opts.start + opts.dur);
  }
  gain.gain.setValueAtTime(0.0001, opts.start);
  gain.gain.exponentialRampToValueAtTime(peak, opts.start + attack);
  gain.gain.exponentialRampToValueAtTime(0.0001, opts.start + opts.dur);
  osc.connect(gain);
  gain.connect(c.destination);
  osc.start(opts.start);
  osc.stop(opts.start + opts.dur + 0.02);
}

/** Call from a user gesture so later beeps are allowed. */
export function unlockSfx(): void {
  const c = getCtx();
  if (!c) return;
  if (c.state === 'suspended') void c.resume();
}

/** Keep trying to unlock on first taps (iOS/Android autoplay policy). */
export function ensureSfxGestureUnlock(): void {
  if (unlockWired) return;
  unlockWired = true;
  const once = () => {
    unlockSfx();
    window.removeEventListener('pointerdown', once, true);
    window.removeEventListener('touchstart', once, true);
    window.removeEventListener('keydown', once, true);
  };
  window.addEventListener('pointerdown', once, true);
  window.addEventListener('touchstart', once, true);
  window.addEventListener('keydown', once, true);
}

export function isSfxMuted(): boolean {
  return muted;
}

export function setSfxMuted(value: boolean): void {
  muted = value;
  saveMuted(value);
  if (!value) unlockSfx();
}

export function toggleSfxMuted(): boolean {
  setSfxMuted(!muted);
  return muted;
}

/** Countdown tick: 3 · 2 · 1 */
export async function playCountdownTick(sec: number): Promise<void> {
  const c = await ensureRunning();
  if (!c) return;
  const t0 = c.currentTime;
  const freq = sec >= 3 ? 660 : sec === 2 ? 740 : 880;
  tone(c, { type: 'triangle', freq, start: t0, dur: 0.11, peak: 0.2 });
}

/** Countdown finished — fight start */
export async function playCountdownGo(): Promise<void> {
  const c = await ensureRunning();
  if (!c) return;
  const t0 = c.currentTime;
  tone(c, { type: 'triangle', freq: 520, freqEnd: 780, start: t0, dur: 0.22, peak: 0.26 });
  tone(c, { type: 'sine', freq: 1040, start: t0 + 0.08, dur: 0.18, peak: 0.14 });
}

/**
 * Rep counted — soft “hit” (not the old harsh square beep).
 * Short low thump + bright sparkle.
 */
export async function playRepBeep(): Promise<void> {
  const c = await ensureRunning();
  if (!c) return;
  const t0 = c.currentTime;
  tone(c, {
    type: 'sine',
    freq: 180,
    freqEnd: 90,
    start: t0,
    dur: 0.14,
    peak: 0.32,
    attack: 0.006
  });
  tone(c, {
    type: 'triangle',
    freq: 620,
    freqEnd: 420,
    start: t0 + 0.02,
    dur: 0.1,
    peak: 0.16,
    attack: 0.008
  });
}

/** Boss enters / cutscene */
export async function playBossFanfare(): Promise<void> {
  const c = await ensureRunning();
  if (!c) return;
  const t0 = c.currentTime;
  tone(c, {
    type: 'sawtooth',
    freq: 110,
    freqEnd: 220,
    start: t0,
    dur: 0.35,
    peak: 0.28,
    attack: 0.02
  });
  tone(c, { type: 'triangle', freq: 330, start: t0 + 0.12, dur: 0.28, peak: 0.2 });
  tone(c, { type: 'sine', freq: 660, start: t0 + 0.22, dur: 0.35, peak: 0.16 });
}

/** Arena / challenge victory */
export async function playArenaVictory(): Promise<void> {
  const c = await ensureRunning();
  if (!c) return;
  const t0 = c.currentTime;
  tone(c, { type: 'triangle', freq: 523, start: t0, dur: 0.18, peak: 0.22 });
  tone(c, { type: 'triangle', freq: 659, start: t0 + 0.14, dur: 0.2, peak: 0.24 });
  tone(c, { type: 'triangle', freq: 784, start: t0 + 0.3, dur: 0.35, peak: 0.26 });
  tone(c, { type: 'sine', freq: 1046, start: t0 + 0.42, dur: 0.4, peak: 0.14 });
}

export function soundToggleIcon(isMuted: boolean): string {
  if (isMuted) {
    return `<svg viewBox="0 0 24 24" width="20" height="20" aria-hidden="true" fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round"><path d="M11 5 6 9H3v6h3l5 4V5z"/><path d="m23 9-6 6"/><path d="m17 9 6 6"/></svg>`;
  }
  return `<svg viewBox="0 0 24 24" width="20" height="20" aria-hidden="true" fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round"><path d="M11 5 6 9H3v6h3l5 4V5z"/><path d="M19.07 4.93a10 10 0 0 1 0 14.14"/><path d="M15.54 8.46a5 5 0 0 1 0 7.07"/></svg>`;
}
