/**
 * 1€ filter (Casiez et al.) — adaptive low-pass for noisy pose signals.
 * Low beta / minCutoff → smooth (slow channel).
 * Higher beta / minCutoff → reactive (fast channel).
 */
export class OneEuroFilter {
  private xPrev: number | null = null;
  private dxPrev = 0;
  private tPrev: number | null = null;

  constructor(
    private minCutoff = 1.0,
    private beta = 0.007,
    private dCutoff = 1.0
  ) {}

  /** @param x value; @param tMs timestamp in milliseconds */
  filter(x: number, tMs: number): number {
    if (this.tPrev == null || this.xPrev == null) {
      this.tPrev = tMs;
      this.xPrev = x;
      this.dxPrev = 0;
      return x;
    }

    const dt = Math.max(1e-3, (tMs - this.tPrev) / 1000);
    const dx = (x - this.xPrev) / dt;
    const edx = this.smooth(dx, this.dxPrev, this.alpha(dt, this.dCutoff));
    this.dxPrev = edx;

    const cutoff = this.minCutoff + this.beta * Math.abs(edx);
    const filtered = this.smooth(x, this.xPrev, this.alpha(dt, cutoff));
    this.xPrev = filtered;
    this.tPrev = tMs;
    return filtered;
  }

  reset(x?: number): void {
    this.xPrev = x ?? null;
    this.dxPrev = 0;
    this.tPrev = null;
  }

  value(): number | null {
    return this.xPrev;
  }

  private alpha(dt: number, cutoff: number): number {
    const tau = 1 / (2 * Math.PI * cutoff);
    return 1 / (1 + tau / dt);
  }

  private smooth(x: number, prev: number, a: number): number {
    return a * x + (1 - a) * prev;
  }
}
