/** Рисованные иконки в стиле Легиона (камень / золото / багрянец). */

import type { ExerciseId } from './exercises';
import type { Level, TierId } from './levels';

const GOLD = '#d4af37';
const GOLD_LIGHT = '#f0d878';
const CRIMSON = '#b91c1c';
const STONE = '#2a1c12';
const INK = '#0c0806';
const SKIN = '#c4a882';
const SKIN_SHADOW = '#8a6a4a';

function esc(s: string): string {
  return s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/"/g, '&quot;');
}

/** Квадратная иконка упражнения — SVG для плитки. */
export function exerciseIconSvg(id: ExerciseId): string {
  if (id === 'squat') {
    return `<svg class="ex-art" viewBox="0 0 64 64" aria-hidden="true" xmlns="http://www.w3.org/2000/svg">
  <defs>
    <linearGradient id="exSqRim" x1="0" y1="0" x2="1" y2="1">
      <stop offset="0" stop-color="${GOLD_LIGHT}"/><stop offset="1" stop-color="#8a6a1a"/>
    </linearGradient>
    <linearGradient id="exSqPlate" x1="0.5" y1="0" x2="0.5" y2="1">
      <stop offset="0" stop-color="#3a2a1c"/><stop offset="1" stop-color="${INK}"/>
    </linearGradient>
  </defs>
  <rect x="2" y="2" width="60" height="60" rx="10" fill="url(#exSqPlate)" stroke="url(#exSqRim)" stroke-width="2.2"/>
  <path d="M18 48h28" stroke="${GOLD}" stroke-width="2" stroke-linecap="round" opacity="0.45"/>
  <!-- body squat -->
  <ellipse cx="32" cy="18" rx="6.5" ry="7" fill="${SKIN}" stroke="${INK}" stroke-width="1"/>
  <path d="M32 25v6" stroke="${SKIN}" stroke-width="5" stroke-linecap="round"/>
  <path d="M26 30h12l2 8H24z" fill="${CRIMSON}" stroke="${GOLD}" stroke-width="1"/>
  <path d="M24 38 L16 50 M40 38 L48 50" stroke="${SKIN_SHADOW}" stroke-width="4.5" stroke-linecap="round"/>
  <path d="M16 50h8 M40 50h8" stroke="${GOLD}" stroke-width="2.2" stroke-linecap="round"/>
  <path d="M22 31 L14 36 M42 31 L50 36" stroke="${SKIN}" stroke-width="3.2" stroke-linecap="round"/>
  <circle cx="46" cy="12" r="5" fill="${CRIMSON}" stroke="${GOLD}" stroke-width="1.2"/>
  <path d="M46 9v6M43 12h6" stroke="${GOLD_LIGHT}" stroke-width="1.2"/>
</svg>`;
  }

  // pushup
  return `<svg class="ex-art" viewBox="0 0 64 64" aria-hidden="true" xmlns="http://www.w3.org/2000/svg">
  <defs>
    <linearGradient id="exPuRim" x1="0" y1="0" x2="1" y2="1">
      <stop offset="0" stop-color="${GOLD_LIGHT}"/><stop offset="1" stop-color="#8a6a1a"/>
    </linearGradient>
    <linearGradient id="exPuPlate" x1="0.5" y1="0" x2="0.5" y2="1">
      <stop offset="0" stop-color="#3a2a1c"/><stop offset="1" stop-color="${INK}"/>
    </linearGradient>
  </defs>
  <rect x="2" y="2" width="60" height="60" rx="10" fill="url(#exPuPlate)" stroke="url(#exPuRim)" stroke-width="2.2"/>
  <path d="M10 46h44" stroke="${GOLD}" stroke-width="2" stroke-linecap="round" opacity="0.4"/>
  <!-- plank figure -->
  <ellipse cx="48" cy="28" rx="6" ry="5.5" fill="${SKIN}" stroke="${INK}" stroke-width="1"/>
  <path d="M42 30 L18 34" stroke="${CRIMSON}" stroke-width="7" stroke-linecap="round"/>
  <path d="M18 34 L12 42 M28 33 L24 44" stroke="${SKIN_SHADOW}" stroke-width="3.5" stroke-linecap="round"/>
  <path d="M40 31 L46 42" stroke="${SKIN}" stroke-width="3.2" stroke-linecap="round"/>
  <circle cx="12" cy="42" r="2.2" fill="${GOLD}"/>
  <circle cx="24" cy="44" r="2.2" fill="${GOLD}"/>
  <circle cx="46" cy="42" r="2" fill="${GOLD}"/>
  <path d="M14 22h10l-2 4H16z" fill="${CRIMSON}" stroke="${GOLD}" stroke-width="1"/>
</svg>`;
}

const TIER_ACCENT: Record<TierId, string> = {
  recruit: '#6ee7b7',
  legionnaire: '#60a5fa',
  gladiator: '#fbbf24',
  centurion: '#fb923c',
  titan: '#fb7185',
  emperor: '#c084fc'
};

function hashSeed(s: string): number {
  let h = 0;
  for (let i = 0; i < s.length; i++) h = (h * 31 + s.charCodeAt(i)) | 0;
  return Math.abs(h);
}

/** Портрет босса / чемпиона уровня — bust в шлеме. */
export function levelBossPortraitSvg(level: Level): string {
  const foe = level.foes[level.foes.length - 1]!;
  const seed = hashSeed(foe.id);
  const accent = TIER_ACCENT[level.tierId] ?? GOLD;
  const isBoss = level.hasBoss;
  const crest = seed % 3;
  const uid = esc(level.id.replace(/[^a-z0-9-]/gi, ''));

  const crestPath =
    crest === 0
      ? `<path d="M32 6 L36 18 H28 Z" fill="${CRIMSON}" stroke="${GOLD}" stroke-width="1"/>`
      : crest === 1
        ? `<path d="M32 4 L34 16 H30 Z" fill="${accent}" stroke="${GOLD}" stroke-width="1"/><path d="M28 8h8" stroke="${GOLD}" stroke-width="1.5"/>`
        : `<circle cx="32" cy="10" r="5" fill="${CRIMSON}" stroke="${GOLD}" stroke-width="1.2"/><path d="M32 7v6M29 10h6" stroke="${GOLD_LIGHT}" stroke-width="1"/>`;

  const laurel = isBoss
    ? `<path d="M14 36c4-10 10-14 18-14M50 36c-4-10-10-14-18-14" fill="none" stroke="${GOLD}" stroke-width="1.6" opacity="0.85"/>`
    : '';

  const shoulderPad = isBoss
    ? `<path d="M12 48 L22 42 L22 56 Z" fill="${accent}" stroke="${GOLD}" stroke-width="1"/><path d="M52 48 L42 42 L42 56 Z" fill="${accent}" stroke="${GOLD}" stroke-width="1"/>`
    : `<path d="M14 50 L22 44 L22 56 Z" fill="${STONE}" stroke="${GOLD}" stroke-width="1"/><path d="M50 50 L42 44 L42 56 Z" fill="${STONE}" stroke="${GOLD}" stroke-width="1"/>`;

  const helmExtra =
    level.stageIndex >= 8
      ? `<path d="M20 28 Q32 22 44 28" fill="none" stroke="${GOLD_LIGHT}" stroke-width="1.4"/>`
      : '';

  const eyesY = 34;
  const brow =
    seed % 2 === 0
      ? `<path d="M24 ${eyesY - 4}h6M34 ${eyesY - 4}h6" stroke="${INK}" stroke-width="1.5" stroke-linecap="round"/>`
      : `<path d="M24 ${eyesY - 3}h6M34 ${eyesY - 4}h6" stroke="${INK}" stroke-width="1.6" stroke-linecap="round"/>`;

  return `<svg class="boss-art" viewBox="0 0 64 64" aria-hidden="true" xmlns="http://www.w3.org/2000/svg">
  <defs>
    <radialGradient id="bg-${uid}" cx="40%" cy="30%" r="70%">
      <stop offset="0%" stop-color="${accent}" stop-opacity="0.35"/>
      <stop offset="55%" stop-color="${STONE}"/>
      <stop offset="100%" stop-color="${INK}"/>
    </radialGradient>
    <linearGradient id="helm-${uid}" x1="0.5" y1="0" x2="0.5" y2="1">
      <stop offset="0" stop-color="${GOLD_LIGHT}"/>
      <stop offset="0.45" stop-color="${GOLD}"/>
      <stop offset="1" stop-color="#6b4e12"/>
    </linearGradient>
  </defs>
  <circle cx="32" cy="32" r="30" fill="url(#bg-${uid})" stroke="${GOLD}" stroke-width="2"/>
  ${laurel}
  <!-- neck / armor -->
  <path d="M22 48 Q32 54 42 48 L44 60 H20 Z" fill="#3a2418" stroke="${GOLD}" stroke-width="1.2"/>
  <path d="M24 52h16" stroke="${accent}" stroke-width="2" opacity="0.8"/>
  ${shoulderPad}
  <!-- head -->
  <ellipse cx="32" cy="36" rx="11" ry="12" fill="${SKIN}" stroke="${INK}" stroke-width="1"/>
  ${brow}
  <circle cx="27" cy="${eyesY}" r="1.6" fill="${INK}"/>
  <circle cx="37" cy="${eyesY}" r="1.6" fill="${INK}"/>
  <path d="M29 40h6" stroke="${SKIN_SHADOW}" stroke-width="1.2" stroke-linecap="round"/>
  <!-- helmet -->
  <path d="M18 32 Q18 16 32 14 Q46 16 46 32 L44 38 H20 Z" fill="url(#helm-${uid})" stroke="${INK}" stroke-width="1"/>
  <path d="M20 30h24" stroke="${INK}" stroke-width="1" opacity="0.35"/>
  <path d="M22 28 Q32 34 42 28" fill="none" stroke="${CRIMSON}" stroke-width="2.2"/>
  ${helmExtra}
  ${crestPath}
  ${
    isBoss
      ? `<circle cx="32" cy="32" r="29" fill="none" stroke="${GOLD_LIGHT}" stroke-width="1.2" stroke-dasharray="3 3" opacity="0.7"/>`
      : ''
  }
</svg>`;
}

export function challengePortraitSvg(color: string, seedKey: string): string {
  const seed = hashSeed(seedKey);
  const uid = esc(seedKey.replace(/[^a-z0-9-]/gi, '') || 'ch');
  return `<svg class="boss-art" viewBox="0 0 64 64" aria-hidden="true" xmlns="http://www.w3.org/2000/svg">
  <defs>
    <radialGradient id="cbg-${uid}" cx="40%" cy="30%" r="70%">
      <stop offset="0%" stop-color="${color}" stop-opacity="0.4"/>
      <stop offset="100%" stop-color="${INK}"/>
    </radialGradient>
  </defs>
  <circle cx="32" cy="32" r="30" fill="url(#cbg-${uid})" stroke="${GOLD}" stroke-width="2"/>
  <ellipse cx="32" cy="36" rx="11" ry="12" fill="${SKIN}"/>
  <path d="M18 30 Q18 15 32 13 Q46 15 46 30 L42 36 H22 Z" fill="${GOLD}" stroke="${INK}" stroke-width="1"/>
  <path d="M32 6 L36 16 H28 Z" fill="${CRIMSON}" stroke="${GOLD}" stroke-width="1"/>
  <circle cx="27" cy="34" r="1.5" fill="${INK}"/><circle cx="37" cy="34" r="1.5" fill="${INK}"/>
  <path d="M22 48 Q32 56 42 48 L44 60 H20 Z" fill="#3a2418" stroke="${GOLD}" stroke-width="1"/>
  ${seed % 2 === 0 ? `<path d="M14 40h8M42 40h8" stroke="${color}" stroke-width="3"/>` : ''}
</svg>`;
}
